B.yy={Arquebusier:0,Barde:1,"R\xf4deur":2,Voleur:3,Barbare:4,Chevalier:5,Guerrier:6,Ensorceleur:7,Forgesort:8,Magicien:9,Sorcier:10,Druide:11,Moine:12,"Pr\xeatre":13}
B.mA=new A.bg(B.yy,["Aventurier","Aventurier","Aventurier","Aventurier","Combattant","Combattant","Combattant","Mage","Mage","Mage","Mage","Mystique","Mystique","Mystique"],t.li)
B.KK=new A.t(1,"M\xe9canismes","","L'arquebusier ajoute son rang + 2 \xe0 tous les tests visant \xe0 r\xe9parer ou \xe0 comprendre des m\xe9canismes (cela inclut le fait de d\xe9samorcer des pi\xe8ges m\xe9caniques et de manipuler des armes de si\xe8ge). Il obtient un d\xe9 bonus \xe0 tous les tests d'attaque avec des armes de si\xe8ge (baliste, couleuvrine, canon, tr\xe9buchet, catapulte, etc.).",!1)
B.NS=new A.t(2,"Arme \xe0 r\xe9p\xe9tition","","L'arquebusier modifie jusqu'\xe0 deux armes de son choix pour les doter de chargeurs. La capacit\xe9 du chargeur est \xe9gale \xe0 [2 + INT] et elle augmente de 1 projectile suppl\xe9mentaire chaque fois que le personnage atteint le rang 3 dans une voie d'arquebusier. Chaque chargeur doit \xeatre ensuite recharg\xe9 au rythme d'une action limit\xe9e (L) par projectile.",!1)
B.Kx=new A.t(3,"Tir de barrage","L","L'arquebusier surveille une zone de 20 m de large face \xe0 lui. Si une cr\xe9ature se d\xe9place dans cette zone avant son prochain tour, il peut faire une attaque \xe0 distance. En cas de succ\xe8s la victime choisit entre deux possibilit\xe9s : soit elle subit le double des dommages, soit elle termine son tour et son d\xe9placement \xe0 l'endroit de l'attaque et ne subit pas de dommages. L'arquebusier peut effectuer un tir de barrage sur plusieurs cr\xe9atures durant le round, tant qu'il n'a pas besoin de recharger.",!1)
B.Lg=new A.t(4,"Canon double","","L'arquebusier peut bricoler ses armes \xe0 poudre (mais pas une couleuvrine) pour les doter d'un second canon. Il double le d\xe9 de DM de l'arme (mais pas les d\xe9s bonus ni les bonus). Il doit recharger chaque canon individuellement (un canon double consomme 2 projectiles). En cas de critique le d\xe9 est tripl\xe9 (au lieu de \xd74). Ce type d'arme poss\xe8de une double d\xe9tente et il reste possible de d\xe9charger un seul canon \xe0 la fois.",!1)
B.JO=new A.t(5,"Couleuvrine","L","L'arquebusier obtient une couleuvrine (un petit canon portatif). Sur un test d'attaque \xe0 distance r\xe9ussi (d\xe9 bonus), la couleuvrine inflige [5d4\xb0 + INT] DM \xe0 une port\xe9e de 100 m. Il faut ensuite deux rounds (L) pour la recharger. C'est une arme encombrante et il est impossible de transporter plus d'une couleuvrine.",!1)
B.a1c=A.a(s([B.KK,B.NS,B.Kx,B.Lg,B.JO]),t.P)
B.alq=new A.b5("arquebusier_voie-de-l-artilleur","Voie de l'Artilleur",B.a1c)
B.My=new A.t(1,"Joli coup","","L'arquebusier ignore la p\xe9nalit\xe9 appliqu\xe9e pour une couverture partielle de sa cible (-2 au test devient aucun malus) et r\xe9duit la p\xe9nalit\xe9 pour une couverture importante \xe0 -2 (au lieu de -5).",!1)
B.JC=new A.t(2,"D\xe9faut dans la cuirasse","A","L'arquebusier utilise une action d'attaque pour trouver le point faible de son adversaire et le viser. Au prochain round*, il r\xe9alise ses attaques \xe0 distance sur cette cible contre une DEF de [10 + AGI de la cible] et il peut ignorer sa r\xe9sistance aux DM ou sa r\xe9duction des DM (sauf si cette derni\xe8re est acquise parce que la cible est immat\xe9rielle : ombre, fant\xf4me, etc.). *Si l'arquebusier utilise la capacit\xe9 Combat de masse pour son action d'attaque en d\xe9but de round, alors la capacit\xe9 s'applique seulement aux tirs du round en cours.",!1)
B.Jl=new A.t(3,"Tir pr\xe9cis","","L'arquebusier inflige des critiques sur 19-20 sur ses attaques avec une arme \xe0 distance. La plage de critique passe \xe0 18-20 \xe0 partir du rang 5.",!1)
B.Mu=new A.t(4,"Tireur d'\xe9lite","L","L'arquebusier prend le temps d'ajuster une cible au loin (distance minimum de 10 m). Il double la port\xe9e de son arme et ajoute +2d4\xb0 aux DM. Il ne peut pas utiliser cette capacit\xe9 s'il est au contact d'un adversaire ou dans une position instable (par exemple dans un v\xe9hicule).",!1)
B.Mw=new A.t(5,"Tir fatal","L","S'il tire sur une cr\xe9ature dont le niveau (NC) est inf\xe9rieur \xe0 la moiti\xe9 du sien (arrondi au sup\xe9rieur), l'arquebusier peut faire un test d'INT difficult\xe9 [10 + NC de la cr\xe9ature]. En cas de r\xe9ussite, elle est morte. Dans tous les autres cas, elle subit les DM normaux.",!1)
B.a_C=A.a(s([B.My,B.JC,B.Jl,B.Mu,B.Mw]),t.P)
B.alH=new A.b5("arquebusier_voie-de-la-precision","Voie de la Pr\xe9cision",B.a_C)
B.KQ=new A.t(1,"Tir de grenaille","L","L'arquebusier sait r\xe9aliser un m\xe9lange de poudre et de grenaille. Quand il charge une arme \xe0 poudre, il peut choisir d'utiliser ce m\xe9lange \xe0 la place d'une munition normale (il doit l'annoncer au moment o\xf9 il charge). Lorsqu'il tire cette munition (L), il fait un seul test d'attaque contre toutes les cibles lui faisant face dans un c\xf4ne de 10 m de long et sur 5 m de large. Toutes les cibles dont il atteint la DEF subissent la moiti\xe9 des DM habituels. De plus, le personnage ajoute son rang + 2 \xe0 tous les tests d'artificier (par exemple pour fabriquer et tirer des feux d'artifice).",!1)
B.LT=new A.t(2,"D\xe9molition","","L'arquebusier peut pr\xe9parer un explosif qui lui permet de d\xe9molir facilement des structures. Il lui faut 3 rounds complets pour pr\xe9parer et poser son explosif. Celui-ci inflige \xe0 la structure [3d4\xb0 + INT] DM et ignore la moiti\xe9 de sa RD (et seulement 2d4\xb0 DM dans un rayon de 2 m). Chaque jour, l'arquebusier peut utiliser un nombre de charges explosives \xe9gal au rang dans la voie. Ces charges permettent indiff\xe9remment d'utiliser les capacit\xe9s D\xe9molition, Pi\xe8ge explosif ou Boulet explosif.",!1)
B.Og=new A.t(3,"Poudre puissante","","L'arquebusier sait pr\xe9parer une poudre plus puissante, il ajoute +10 m \xe0 la port\xe9e et +1 aux DM des armes \xe0 poudre. Le bonus aux DM augmente de +1 \xe0 chaque fois que le personnage atteint le rang 5 dans une voie d'arquebusier. De plus, sa poudre est magique et elle permet \xe0 ses projectiles d'affecter les cr\xe9atures immunis\xe9es aux armes non magiques.",!1)
B.Oe=new A.t(4,"Pi\xe8ge explosif","L","Il faut 1 min \xe0 l'arquebusier pour installer un pi\xe8ge qui explose dans un rayon de 5 m en infligeant [5d4\xb0 + INT] DM de feu (test d'AGI difficult\xe9 15 pour ne subir que la moiti\xe9 des DM). Le pi\xe8ge est d\xe9clench\xe9 \xe0 l'intrusion de toute cr\xe9ature dans une zone d'un \xe0 deux m\xe8tres autour du pi\xe8ge. Une cr\xe9ature peut d\xe9tecter le pi\xe8ge avec un test d'INT difficult\xe9 [15 + INT de l'arquebusier] avant de le d\xe9clencher.",!1)
B.Km=new A.t(5,"Boulet explosif","L","L'arquebusier sait fabriquer et lancer de petites boules de m\xe9tal garnies de poudre d'une port\xe9e de 20 m qui explosent dans un rayon de 5 m en infligeant [4d4\xb0 + INT] DM perforants, divis\xe9s par 2 pour les victimes qui r\xe9ussissent un test d'AGI difficult\xe9 10. Ceux qui ratent le test sont de plus aveugl\xe9s un round par le flash lumineux de l'explosion.",!1)
B.a1Y=A.a(s([B.KQ,B.LT,B.Og,B.Oe,B.Km]),t.P)
B.alr=new A.b5("arquebusier_voie-des-explosifs","Voie des Explosifs",B.a1Y)
B.KU=new A.t(1,"Pilier de bar","","L'arquebusier obtient un bonus \xe9gal \xe0 son rang + 2 aux tests d'interaction sociale dans les tavernes ou les auberges (renseignement, n\xe9gociation, s\xe9duction, etc.) ainsi que pour r\xe9sister aux effets de l'alcool. De plus, il inflige 1d4\xb0 DM \xe0 mains nues (non l\xe9tal) et il divise par 2 tous les DM non l\xe9taux qu'on lui inflige.",!1)
B.KL=new A.t(2,"Mort ou vif","L","L'arquebusier effectue une attaque au contact ou \xe0 distance (avec l'arme en main). Si l'attaque est r\xe9ussie, il inflige ses DM habituels (mais peut choisir d'infliger des DM temporaires) et il choisit entre d\xe9sarmer, renverser ou affaiblir (1d4 rounds) un adversaire dont le NC est inf\xe9rieur au rang atteint dans la voie. Si l'attaque est une r\xe9ussite critique, il peut choisir de cumuler deux effets.",!1)
B.JN=new A.t(3,"Combattant aguerri","","L'arquebusier choisit une capacit\xe9 de rang 1 de son choix de guerrier, de voleur (armure de cuir) ou de r\xf4deur (armure de cuir renforc\xe9). Il gagne aussi +1 en DEF.",!1)
B.K_=new A.t(4,"Constitution h\xe9ro\xefque","","L'arquebusier augmente sa valeur de CON de +1 et il obtient un d\xe9 bonus aux tests de CON.",!1)
B.LC=new A.t(5,"Combat de masse","","Si le combat implique au moins 10 cr\xe9atures actives (en comptant l'arquebusier et ses alli\xe9s), l'arquebusier obtient, au choix, une action d'attaque ou une action de mouvement suppl\xe9mentaire \xe0 son tour. De plus, l'arquebusier gagne +1 en DEF.",!1)
B.a01=A.a(s([B.KU,B.KL,B.JN,B.K_,B.LC]),t.P)
B.alp=new A.b5("arquebusier_voie-du-mercenaire","Voie du Mercenaire",B.a01)
B.IV=new A.t(1,"Plus vite que son ombre","","Si son arme \xe0 poudre est charg\xe9e et tenue en main, l'arquebusier peut tirer avec un bonus de +5 \xe0 son Initiative. De plus, il ne subit plus de d\xe9 malus lorsqu'il tire avec une arme \xe0 poudre ou une arbal\xe8te en \xe9tant engag\xe9 en combat au contact (sauf avec la couleuvrine).",!1)
B.MJ=new A.t(2,"Ajuster le tir","","Apr\xe8s avoir rat\xe9 une attaque \xe0 distance, l'arquebusier d\xe9clare qu'il s'agissait d'un tir de r\xe9glage. Il obtient +5 sur le test de sa prochaine attaque \xe0 distance, si son prochain tir vise la m\xeame cible avant la fin du prochain round.",!1)
B.IM=new A.t(3,"Tir double","L","L'arquebusier est capable de tirer simultan\xe9ment avec une p\xe9toire (ou une arbal\xe8te de poing) dans chaque main avec un malus de -2 \xe0 chaque attaque. S'il d\xe9charge ses deux armes sur la m\xeame cible, il ne subit aucun malus.",!1)
B.Ll=new A.t(4,"Agilit\xe9 h\xe9ro\xefque","","L'arquebusier augmente sa valeur d'AGI de +1 et il obtient un d\xe9 bonus aux tests d'AGI.",!1)
B.NP=new A.t(5,"As de la g\xe2chette","","Lors d'une attaque \xe0 distance avec une arme \xe0 poudre ou une arbal\xe8te, s'il obtient un r\xe9sultat d'attaque sup\xe9rieur ou \xe9gal \xe0 la DEF de son adversaire +10 points, l'arquebusier obtient un bonus de +2d4\xb0 aux DM de son attaque.",!1)
B.a_D=A.a(s([B.IV,B.MJ,B.IM,B.Ll,B.NP]),t.P)
B.akV=new A.b5("arquebusier_voie-du-pistolero","Voie du Pistolero",B.a_D)
B.a2D=A.a(s([B.alq,B.alH,B.alr,B.alp,B.akV]),t.oy)
B.Lb=new A.t(1,"Pr\xe9cision","","Le barde peut remplacer sa FOR par son AGI pour ses tests d'attaque au contact (mais pas aux DM) lorsqu'il emploie une arme l\xe9g\xe8re \xe0 une main (les armes l\xe9g\xe8res sont la dague, l'\xe9p\xe9e courte et la rapi\xe8re).",!1)
B.Lf=new A.t(2,"Feinte","L","Le barde effectue une attaque fictive pour d\xe9s\xe9quilibrer son adversaire et r\xe9alise ensuite une attaque mortelle. Faites un test oppos\xe9 de CHA contre la PER de votre adversaire \xe0 ce round. Au round suivant, vous obtenez un bonus en attaque \xe9gal au double de votre rang dans la voie de l'escrime (+4 au rang 2, par exemple) sur votre premi\xe8re attaque au contact contre cet adversaire et, si votre feinte a r\xe9ussi, +2d4\xb0 aux DM.",!1)
B.Of=new A.t(3,"Intelligence du combat","M","Une fois par combat, le barde peut au choix d\xe9sarmer, renverser ou aveugler pour une dur\xe9e de 1 round un adversaire dont le NC est inf\xe9rieur au sien en emportant un test oppos\xe9 d'INT. S'il a r\xe9ussi une feinte contre cet adversaire \xe0 son tour pr\xe9c\xe9dent, il b\xe9n\xe9ficie d'un bonus de +5 au test d'INT.",!1)
B.Ku=new A.t(4,"Attaque flamboyante","L","Le style de combat du barde est flamboyant et surprenant : il effectue une attaque de contact avec une arme l\xe9g\xe8re et obtient un bonus d'attaque et de DM \xe9gal \xe0 son CHA (en plus de sa FOR ou de son AGI).",!1)
B.Oa=new A.t(5,"Botte mortelle","","Lors d'une attaque au contact avec une arme l\xe9g\xe8re, s'il obtient un r\xe9sultat d'attaque sup\xe9rieur ou \xe9gal \xe0 (la DEF de son adversaire + 10 points), le barde obtient un bonus de +2d4\xb0 aux DM de son attaque (les d\xe9s bonus ne sont jamais multipli\xe9s en cas de critique).",!1)
B.a0q=A.a(s([B.Lb,B.Lf,B.Of,B.Ku,B.Oa]),t.P)
B.aln=new A.b5("barde_voie-de-l-escrime","Voie de l'Escrime",B.a0q)
B.NH=new A.t(1,"Charmant","","Le barde ajoute son rang + 2 aux tests effectu\xe9s pour s\xe9duire, convaincre, mentir ou baratiner. D\xe9sormais, il peut d\xe9penser 1 point de chance pour am\xe9liorer l'action d'un compagnon en vue, ce PC permet d'ajouter [1d4\xb0 + CHA] sur le r\xe9sultat du test (au lieu de +10).",!1)
B.Ly=new A.t(2,"Dentelles et rapi\xe8re","","Le barde ne met pas d'armure, cela ne sied point en soci\xe9t\xe9. Sa seule armure est la dentelle, sa seule d\xe9fense, la rapi\xe8re. Lorsqu'il ne porte aucune armure, le barde ajoute son CHA en DEF (en plus de son AGI), toutefois ce bonus ne peut pas d\xe9passer le rang atteint dans la voie.",!1)
B.Nl=new A.t(3,"Baratineur de g\xe9nie","","Si le barde peut passer 10 minutes avec un humano\xefde dont le niveau est inf\xe9rieur ou \xe9gal \xe0 1 (NC 1), il peut d\xe9penser un 1 PC pour le charmer. La cible r\xe9pond favorablement \xe0 vos requ\xeates dans la limite de ce que ferait un ami et ce lien peut se renforcer avec le temps. Si vous ne partagez pas une langue commune, cela vous co\xfbte 2 PC.",!1)
B.Lm=new A.t(4,"Charisme h\xe9ro\xefque","","Le barde augmente sa valeur de CHA de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CHA. De plus, le barde peut d\xe9sormais utiliser son CHA au lieu de sa VOL pour calculer le nombre de PM dont il dispose.",!1)
B.Mt=new A.t(5,"Suggestion","A","Le barde peut sugg\xe9rer une action \xe0 une cr\xe9ature en r\xe9ussissant un test oppos\xe9 d'attaque magique. En cas de r\xe9ussite, la cr\xe9ature fera tout son possible pour satisfaire cette demande pendant 1 heure ou jusqu'\xe0 avoir r\xe9ussi. Elle \xe9vitera les actions suicidaires (ce qui lui donnerait imm\xe9diatement un test d'INT difficult\xe9 10 pour \xe9chapper au sort). Le sort ne peut pas affecter une cr\xe9ature de niveau sup\xe9rieur ou \xe9gal \xe0 celui du lanceur.",!0)
B.a0c=A.a(s([B.NH,B.Ly,B.Nl,B.Lm,B.Mt]),t.P)
B.ali=new A.b5("barde_voie-de-la-seduction","Voie de la S\xe9duction",B.a0c)
B.Jg=new A.t(1,"Chant des h\xe9ros","L","Le barde peut chanter et inspirer ses compagnons, tous ses alli\xe9s \xe0 port\xe9e de voix et lui obtiennent un bonus de +1 \xe0 tous leurs tests pendant un nombre de minutes \xe9gal \xe0 sa valeur de CHA. Pendant toute la dur\xe9e du sort, il fredonne (action gratuite qui ne l'emp\xeache pas de lancer d'autres sorts de barde). Le bonus passe \xe0 +2 au rang 5. En plus de ce sort, le barde ajoute son rang + 2 aux tests pour jouer d'un instrument de musique ou chanter.",!0)
B.Ls=new A.t(2,"Chant de r\xe9confort","L","Le barde chante ou joue de la musique pendant toute la dur\xe9e d'une r\xe9cup\xe9ration rapide (30 min). Le barde et ses alli\xe9s dans un rayon de 10 m r\xe9cup\xe8rent 1d4\xb0 PV. Les soins passent \xe0 2d4\xb0 au rang 4.",!0)
B.JT=new A.t(3,"Attaque sonore","A","Le barde pousse un cri dont les effets sont d\xe9vastateurs (ou produit un son avec un instrument \xe0 cette m\xeame fin). Il inflige [2d4\xb0 + CHA] DM \xe0 toutes les cibles dans un c\xf4ne de 10 m (de long et de large). Les cibles peuvent diviser les DM par 2 si elles r\xe9ussissent un test de CON difficult\xe9 [10 + CHA du barde].",!0)
B.JR=new A.t(4,"Zone de silence","A","Le barde cr\xe9e une zone de silence fixe de 5 m de diam\xe8tre, jusqu'\xe0 une port\xe9e de 30 m, pendant un nombre de minutes \xe9gal \xe0 sa valeur de CHA. Tous les sons \xe9mis dans cette sph\xe8re sont annul\xe9s. Dans cette zone, il faut r\xe9ussir un test d'INT difficult\xe9 10 pour lancer un sort.",!0)
B.Lw=new A.t(5,"Danse irr\xe9sistible","A","Le barde joue une gigue endiabl\xe9e aux effets magiques. S'il r\xe9ussit un test d'attaque magique oppos\xe9 contre sa cible (port\xe9e 10 m), celle-ci se met \xe0 danser pendant [1d4\xb0 + CHA] rounds, elle subit un d\xe9 malus aux tests d'attaque et -5 en DEF. Si la cible est d'un niveau (NC) sup\xe9rieur ou \xe9gal au barde, elle ne danse qu'un seul round.",!0)
B.a_f=A.a(s([B.Jg,B.Ls,B.JT,B.JR,B.Lw]),t.P)
B.al4=new A.b5("barde_voie-du-musicien","Voie du Musicien",B.a_f)
B.JI=new A.t(1,"Acrobate","","Le barde ajoute son rang + 2 \xe0 tous les tests qu'il effectue pour r\xe9aliser des acrobaties, tenir en \xe9quilibre, faire des sauts ou de l'escalade.",!1)
B.MR=new A.t(2,"Gr\xe2ce f\xe9line","","Le barde gagne son CHA en Initiative et +1 en DEF (+2 au rang 4). De plus, le barde ajoute son rang + 2 aux tests de danse, de mime ou de jonglerie.",!1)
B.Jc=new A.t(3,"Lanceur de couteau","G","Une fois par round, en plus de ses autres actions, le barde peut lancer un couteau sur une cible \xe0 distance (port\xe9e 10 m) en r\xe9ussissant un test d'attaque \xe0 distance. Cette attaque occasionne [1d4 + AGI] DM. Il peut ex\xe9cuter cette action sans p\xe9nalit\xe9, m\xeame s'il est engag\xe9 en combat au contact avec un autre adversaire. Les DM passent \xe0 1d4\xb0 au rang 5.",!1)
B.Li=new A.t(4,"Libert\xe9 d'action","","Le barde est immunis\xe9 \xe0 la peur et \xe0 tous les sorts qui asservissent l'esprit (possession, charme), il est immunis\xe9 aux \xe9tats ralenti et immobilis\xe9.",!1)
B.ME=new A.t(5,"Esquive acrobatique","G","Une fois par round, le barde peut r\xe9aliser une esquive en r\xe9ussissant un test d'attaque \xe0 distance contre une difficult\xe9 \xe9gale au r\xe9sultat obtenu par son adversaire, lors de son attaque. En cas de r\xe9ussite, le barde ne subit aucun DM. Si cette attaque \xe9tait un critique, il subit tout de m\xeame des DM normaux (il annule donc l'effet critique \xab dommages doubl\xe9s \xbb).",!1)
B.a_P=A.a(s([B.JI,B.MR,B.Jc,B.Li,B.ME]),t.P)
B.al8=new A.b5("barde_voie-du-saltimbanque","Voie du Saltimbanque",B.a_P)
B.O9=new A.t(1,"Rumeurs et l\xe9gendes","","\xc0 force de voyager, le barde poss\xe8de une culture g\xe9n\xe9rale tr\xe8s vaste, il ajoute son rang + 2 aux tests d'INT pour se \xab souvenir \xbb d'une information historique, politique, g\xe9ographique ou occulte ou encore pour identifier un objet magique difficult\xe9 (25 \u2013 (2 x niveau de magie de l'objet)).",!1)
B.Js=new A.t(2,"\xc9clectique","","Le barde obtient un bonus de +1 \xe0 tous les tests de comp\xe9tence (absolument tous, de se cacher dans les ombres jusqu'\xe0 forger une \xe9p\xe9e, en passant par traduire une langue ancienne). Ce bonus ne peut se cumuler \xe0 aucun autre bonus de comp\xe9tence sauf celui du rang 1 de la voie de peuple. Il augmente de +1 chaque fois qu'il atteint le rang 4 dans une voie de barde.",!1)
B.KW=new A.t(3,"Attirail","","Le barde poss\xe8de toutes sortes de choses dans son sac ou ses poches. En d\xe9pensant 1 PC, il peut sortir un objet improbable qu'il avait sur lui, mais qui n'est pas inscrit sur sa fiche de PJ (pour une valeur maximale de 10 pa). Il peut aussi bricoler un objet avec trois bouts de ficelles et un clou (syst\xe8me D).",!1)
B.Ka=new A.t(4,"Compr\xe9hension des langues","A","Ce sort permet au barde de lire, \xe9crire et parler une langue vivante \xe9trang\xe8re. Le sort a une dur\xe9e maximale de CHA heures, mais il peut aussi \xeatre lanc\xe9 sur un alli\xe9 au contact et dans ce cas, il ne dure que CHA minutes. \xc0 partir du rang 5, il peut aussi d\xe9chiffrer une inscription dans une langue morte.",!0)
B.Mh=new A.t(5,"D\xe9guisement","A","Ce sort permet au barde de prendre l'apparence de n'importe quelle humano\xefde de taille \xe0 peu pr\xe8s \xe9quivalente (avec une marge d'environ 50 cm). S'il veut imiter une personne en particulier, il lui faudra r\xe9ussir un test de CHA difficult\xe9 15 (20 s'il ne la conna\xeet pas mais l'a seulement vue, 10 s'il la conna\xeet tr\xe8s bien). Le sort a une dur\xe9e maximale de CHA heures, mais il peut aussi \xeatre lanc\xe9 sur un alli\xe9 au contact et dans ce cas, il ne dure que CHA minutes.",!0)
B.a2u=A.a(s([B.O9,B.Js,B.KW,B.Ka,B.Mh]),t.P)
B.alD=new A.b5("barde_voie-du-vagabond","Voie du Vagabond",B.a2u)
B.a2x=A.a(s([B.aln,B.ali,B.al4,B.al8,B.alD]),t.oy)
B.Jn=new A.t(1,"Archer \xe9m\xe9rite","","Le r\xf4deur ajoute sa PER aux DM qu'il inflige \xe0 l'arc et +1 par rang dans la voie en initiative.",!1)
B.KP=new A.t(2,"Tir chirurgical","","Le r\xf4deur peut tirer sur une cible engag\xe9e en m\xeal\xe9e sans p\xe9nalit\xe9 (mais pas sur une cible \xe0 couvert). Il ne risque jamais de toucher un alli\xe9, m\xeame en cas d'\xe9chec critique.",!1)
B.Jf=new A.t(3,"Dans le mille","","Pour une attaque \xe0 distance, le r\xf4deur peut choisir de s'imposer un d\xe9 malus en attaque. Si elle est r\xe9ussie, il ajoute 2d4\xb0 aux DM. Cette capacit\xe9 peut \xeatre utilis\xe9e avec Tir rapide ou Fl\xe8che de mort. Transformez cette capacit\xe9 en action limit\xe9e (L) pour obtenir +3d4\xb0 aux DM au lieu de 2d4\xb0.",!1)
B.Jb=new A.t(4,"Tir rapide","L","Le r\xf4deur peut faire deux attaques \xe0 distance pendant son tour avec un malus de -2.",!1)
B.Mk=new A.t(5,"Fl\xe8che de mort","L","Vous obtenez un d\xe9 bonus en attaque \xe0 distance et vous ajoutez 1d4\xb0 aux DM. Au lieu du d\xe9 bonus et de +1d4\xb0 aux DM, vous pouvez infliger un \xe9tat pr\xe9judiciable de votre choix parmi aveugl\xe9, affaibli, ralenti ou immobilis\xe9 pendant 1 round \xe0 une cible d'un NC inf\xe9rieur au v\xf4tre. Vous ne pouvez infliger chaque \xe9tat pr\xe9judiciable qu'une seule fois par combat.",!1)
B.a0K=A.a(s([B.Jn,B.KP,B.Jf,B.Jb,B.Mk]),t.P)
B.alf=new A.b5("rodeur_voie-de-l-archer","Voie de l'Archer",B.a0K)
B.NZ=new A.t(1,"Survie","","Le r\xf4deur ajoute son rang + 2 \xe0 tous les tests d'escalade et de survie en milieu naturel (s'orienter, trouver un abri et de la nourriture, etc.) dont les tests de r\xe9cup\xe9ration effectu\xe9s chaque nuit. Lorsqu'il dort en milieu naturel, s'il d\xe9pense 1 d\xe9 de r\xe9cup\xe9ration (DR), il gu\xe9rit 1d4\xb0 PV suppl\xe9mentaire (en plus de [DR max + \xbd niveau]).",!1)
B.LN=new A.t(2,"Nature nourrici\xe8re","","Une fois par jour, si le r\xf4deur passe 1d6 h en milieu naturel sauvage (pas dans un champ), il trouve de quoi nourrir une personne par rang pour une journ\xe9e et, s'il r\xe9ussit un test de PER (Survie) difficult\xe9 10, il trouve des plantes m\xe9dicinales pour soigner 1d4\xb0 PV par rang. Les plantes doivent \xeatre utilis\xe9es imm\xe9diatement (10 min de pr\xe9paration et autant pour faire effet) et les d\xe9s peuvent \xeatre r\xe9partis sur plusieurs patients.",!1)
B.LJ=new A.t(3,"Grand pas","G","En milieu naturel, le r\xf4deur obtient +1 en DEF (ce bonus passe \xe0 +2 au rang 5) et 10 m de d\xe9placement en action gratuite (\xe0 son tour de jeu). Enfin, il n'est pas g\xean\xe9 par les terrains difficiles naturels, mais il n'obtient pas alors de d\xe9placement suppl\xe9mentaire.",!1)
B.N3=new A.t(4,"Constitution h\xe9ro\xefque","","Le r\xf4deur augmente sa valeur de CON de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CON.",!1)
B.KO=new A.t(5,"Increvable","L","Une fois par combat, lorsqu'il tombe \xe0 0 PV, le r\xf4deur peut r\xe9cup\xe9rer [4d4\xb0 + CON] PV au d\xe9but de son prochain tour. Lorsqu'il se rel\xe8ve, il b\xe9n\xe9ficie d'un bonus de +5 en DEF pendant 1 round et il se d\xe9barrasse de tous les \xe9tats pr\xe9judiciables non permanents qui l'affectent.",!1)
B.a1K=A.a(s([B.NZ,B.LN,B.LJ,B.N3,B.KO]),t.P)
B.alC=new A.b5("rodeur_voie-de-la-survie","Voie de la Survie",B.a1K)
B.MX=new A.t(1,"Attaque \xe0 suivre","G","Une fois par round, lorsqu'il rate une attaque de sa main principale, le r\xf4deur peut porter une attaque en action gratuite de son autre main avec une arme parmi dague (dague de lancer), hachette (hache de lancer) ou \xe9p\xe9e courte. S'il utilise une arme \xe0 une main en dehors de cette liste, il subit un d\xe9 malus sur cette attaque.",!1)
B.NK=new A.t(2,"Parade crois\xe9e","","Le r\xf4deur obtient un bonus de +1 en DEF lorsqu'il combat avec une arme dans chaque main. Ce bonus passe \xe0 +2 au rang 5 de la voie. Au d\xe9but de son tour, s'il renonce \xe0 toute attaque de la main secondaire, il double ce bonus jusqu'\xe0 son prochain tour.",!1)
B.Ns=new A.t(3,"Droite-gauche","G","Une fois par round, lorsqu'il attaque de sa main principale, le r\xf4deur obtient aussi une attaque de sa main secondaire en action gratuite. Si la cible n'est pas la m\xeame que celle de la main principale, il subit un d\xe9 malus au test. Cette capacit\xe9 se substitue \xe0 Attaque \xe0 suivre.",!1)
B.IN=new A.t(4,"Combattant h\xe9ro\xefque","","Le r\xf4deur augmente sa valeur d'AGI de +1 et obtient un d\xe9 bonus aux tests d'AGI (lancer deux d20 et conserver le plus haut r\xe9sultat). Alternativement, le personnage peut choisir d'augmenter sa valeur de FOR de +1 (pas de d\xe9 bonus aux tests) et peut d\xe9sormais attaquer avec la m\xeame arme dans la main secondaire sans subir de d\xe9 malus (par exemple deux \xe9p\xe9es longues).",!1)
B.Nj=new A.t(5,"Double peine","","Si les deux armes du r\xf4deur atteignent la m\xeame cible lors d'un m\xeame tour, le personnage obtient un effet d'encha\xeenement qui ajoute 1d4\xb0 DM \xe0 l'une des deux attaques de son choix.",!1)
B.a_F=A.a(s([B.MX,B.NK,B.Ns,B.IN,B.Nj]),t.P)
B.alv=new A.b5("rodeur_voie-du-combat-a-deux-armes","Voie du Combat \xe0 Deux Armes",B.a_F)
B.J_=new A.t(1,"Le loup","","Le r\xf4deur obtient un loup pour compagnon animal. En combat, le loup attaque en m\xeame temps que le r\xf4deur. Le loup comprend des ordres simples (garde, reste, apporte, attaque, etc.). | AGI +1 | CON +1* | FOR +2 | PER +2* | CHA -2 | INT -3 | VOL +2 | D\xe9fense : [12 + rang dans la voie] PV : [niveau du r\xf4deur \xd7 4] Initiative : [Init. du r\xf4deur] Attaque au contact : [attaque magique du r\xf4deur] DM 1d4+2 *Le loup obtient un d\xe9 bonus sur ses tests.",!1)
B.Lh=new A.t(2,"Travail d'\xe9quipe","","Lorsque le loup et le r\xf4deur sont au contact, le loup obtient un d\xe9 bonus en attaque et le r\xf4deur obtient un d\xe9 bonus aux tests effectu\xe9s pour pister ou pour \xe9viter d'\xeatre surpris (Vigilance).",!1)
B.Nz=new A.t(3,"Lien empathique","L","Le r\xf4deur peut communiquer avec son loup par t\xe9l\xe9pathie et le gu\xe9rir \xe0 distance en d\xe9pensant ses propres PV (1 PV du r\xf4deur pour 1 PV octroy\xe9 au loup, sans limitation de quantit\xe9) au prix d'une action limit\xe9e. En milieu naturel, le r\xf4deur obtient +1 en DEF.",!1)
B.Jt=new A.t(4,"Loup alpha","","Le loup du r\xf4deur devient un sp\xe9cimen particuli\xe8rement puissant. | CON +3* | FOR +5 | D\xe9fense : 18 PV : [Niveau \xd7 5] DM : 1d4\xb0+5",!1)
B.O2=new A.t(5,"Tactiques de meute","","Lorsque le loup attaque la m\xeame cible que le r\xf4deur, il obtient un bonus de 1d4\xb0 aux DM. Chaque fois que le r\xf4deur d\xe9pense 1 PV pour soigner son loup, le loup r\xe9cup\xe8re 2 PV. De plus, le r\xf4deur et son loup augmentent leur DEF de +1 chaque fois que le personnage atteint le rang 5 dans une voie de r\xf4deur (celle-ci incluse).",!1)
B.a0i=A.a(s([B.J_,B.Lh,B.Nz,B.Jt,B.O2]),t.P)
B.alw=new A.b5("rodeur_voie-du-compagnon-animal","Voie du Compagnon Animal",B.a0i)
B.Jj=new A.t(1,"\xc9claireur","","En milieu naturel, le r\xf4deur ajoute son rang + 2 \xe0 ses tests de discr\xe9tion et de vigilance ainsi qu'aux tests pour pister. De plus, le r\xf4deur peut remplacer le bonus de +1 PC de la famille des aventuriers par un bonus de +1 DR si le joueur le souhaite.",!1)
B.Mf=new A.t(2,"Attaque \xe9clair","L","Le r\xf4deur peut effectuer une attaque au contact tr\xe8s rapide. Il ajoute son AGI en attaque et aux DM pour cette attaque. \xc0 partir du rang 5, cette attaque peut \xeatre associ\xe9e \xe0 10 m de d\xe9placement.",!1)
B.NJ=new A.t(3,"Chasseur \xe9m\xe9rite","","Le r\xf4deur obtient +1d4\xb0 aux DM de ses attaques au contact ou \xe0 distance lorsqu'il combat des animaux (m\xeame g\xe9ants). Chaque fois qu'il atteint le rang 5 dans une voie de r\xf4deur, il peut choisir un ennemi jur\xe9 contre lequel il obtient le m\xeame avantage parmi les goblino\xefdes, les g\xe9ants, les dragons, les morts-vivants, les insectes* (arthropodes inclus), les d\xe9mons.",!1)
B.Kk=new A.t(4,"Perception h\xe9ro\xefque","","Le r\xf4deur augmente sa valeur de PER de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de PER.",!1)
B.JF=new A.t(5,"Repli","L","En milieu naturel, le r\xf4deur se d\xe9place de 30 m en s'\xe9loignant de ses ennemis. Le joueur fait un test d'AGI difficult\xe9 10, en cas de succ\xe8s, il dispara\xeet de la vue de ses poursuivants. Il peut s'\xe9loigner ou rester cach\xe9 sans risque d'\xeatre retrouv\xe9 ou rattrap\xe9. Si le terrain est d\xe9couvert (d\xe9sert, plaine), la difficult\xe9 passe \xe0 15.",!1)
B.a05=A.a(s([B.Jj,B.Mf,B.NJ,B.Kk,B.JF]),t.P)
B.alB=new A.b5("rodeur_voie-du-traqueur","Voie du Traqueur",B.a05)
B.a2k=A.a(s([B.alf,B.alC,B.alv,B.alw,B.alB]),t.oy)
B.O7=new A.t(1,"Discr\xe9tion","","Le voleur ajoute son rang + 2 \xe0 tous les tests de discr\xe9tion, de d\xe9guisement ou pour cacher une arme sur lui. Il apprend le langage silencieux \xe0 base de signe des voleurs (argotien) et enfin il obtient un d\xe9 bonus en attaque lorsqu'il attaque un adversaire surpris.",!1)
B.Mc=new A.t(2,"Attaque sournoise","L","Une fois par round, quand il attaque un adversaire surpris ou de dos** avec une arme l\xe9g\xe8re, le voleur inflige +2d4\xb0 DM suppl\xe9mentaires. Les DM inflig\xe9s par cette capacit\xe9 augmentent de 1d4\xb0 \xe0 chaque fois qu'il atteint le rang 4 dans une voie de voleur (pour un maximum de 7d4\xb0). Cette capacit\xe9 n\xe9cessite l'utilisation d'une arme l\xe9g\xe8re (dague, \xe9ventuellement lanc\xe9e, \xe9p\xe9e courte, rapi\xe8re) ; dans tous les autres cas, le bonus aux DM est divis\xe9 par deux (cela comprend les armes \xe0 distance).",!1)
B.NV=new A.t(3,"Attaque par surprise","A","Contre un adversaire surpris, le voleur peut r\xe9aliser une attaque sournoise en utilisant une action d'attaque plut\xf4t qu'une action limit\xe9e et il augmente les DM de son attaque sournoise de 2d4\xb0.",!1)
B.J9=new A.t(4,"Disparition","M","Une fois par combat, le voleur peut dispara\xeetre dans un flash lumineux et un nuage de fum\xe9e. Aucun adversaire ne peut l'attaquer pendant qu'il a disparu, mais il peut subir des DM de zone. Il ne r\xe9appara\xeet qu'au d\xe9but de son prochain tour \xe0 une distance maximale de 20 m de sa position initiale. \xc0 ce moment, si le voleur a l'initiative, il peut r\xe9aliser une attaque sournoise.",!1)
B.MU=new A.t(5,"Ouverture mortelle","L","Une fois par combat, le voleur obtient une r\xe9ussite critique automatique contre la cible de son choix. Il profite donc d'une r\xe9ussite automatique, des dommages multipli\xe9s par 2 pr\xe9vus dans ce cas et d'une attaque sournoise (dont les DM ne sont pas doubl\xe9s).",!1)
B.a0k=A.a(s([B.O7,B.Mc,B.NV,B.J9,B.MU]),t.P)
B.akS=new A.b5("voleur_voie-de-l-assassin","Voie de l'Assassin",B.a0k)
B.Mz=new A.t(1,"Baratin","","Le voleur ajoute son rang + 2 aux tests destin\xe9s \xe0 baratiner, s\xe9duire, n\xe9gocier, mentir ou pour trouver un objet au march\xe9 noir. De plus, il devient capable d'utiliser les parchemins ou les baguettes magiques en r\xe9ussissant un test d'attaque magique (L) contre une difficult\xe9 de (10 + (2 x rang du sort inscrit)). En cas d'\xe9chec, le sort n'est pas lanc\xe9 et le voleur peut faire une nouvelle tentative.",!1)
B.Nr=new A.t(2,"Provocation","L","Le voleur ma\xeetrise l'art de se rendre d\xe9sagr\xe9able, voire insupportable. S'il emporte un test oppos\xe9 de CHA contre INT d'un adversaire humano\xefde \xe0 moins de 10 m, il force la cible \xe0 l'attaquer \xe0 son prochain tour. \xc0 ce moment-l\xe0, si le voleur est au contact, il peut riposter par une attaque de contact gratuite pour laquelle il b\xe9n\xe9ficie au choix d'une attaque sournoise ou d'un bonus de 1d4\xb0 aux DM.",!1)
B.J2=new A.t(3,"Souplesse du f\xe9lin","","Le voleur poss\xe8de une d\xe9marche et une fa\xe7on de se d\xe9placer \xe0 la fois \xe9l\xe9gante, f\xe9line et souple. Il ajoute +2 en DEF et en Initiative. Ce bonus passe \xe0 +3 au rang 5. Il lui faut seulement une action de mouvement pour se relever.",!1)
B.K4=new A.t(4,"Charisme h\xe9ro\xefque","","Le voleur augmente sa valeur de CHA de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CHA.",!1)
B.Oi=new A.t(5,"Attaque paralysante","L","Une fois par combat, le voleur peut, en r\xe9ussissant une attaque de contact, paralyser un adversaire humano\xefde de douleur. La cible ne subit aucun DM, mais elle est immobilis\xe9e pendant 1d4 rounds ou, si son NC est inf\xe9rieur \xe0 la moiti\xe9 du niveau du voleur, elle est paralys\xe9e. De plus, le voleur peut d\xe9sormais utiliser au choix l'attaque sournoise (s'il d\xe9tient cette capacit\xe9) ou infliger +1d4\xb0 DM contre tout adversaire immobilis\xe9 ou paralys\xe9.",!1)
B.a09=A.a(s([B.Mz,B.Nr,B.J2,B.K4,B.Oi]),t.P)
B.akK=new A.b5("voleur_voie-de-l-aventurier","Voie de l'Aventurier",B.a09)
B.Kg=new A.t(1,"Agile","","Le voleur ajoute son rang + 2 \xe0 tous tests li\xe9s \xe0 un d\xe9placement (esquive, saut, course, \xe9quilibre, escalade, se glisser entre des barreaux ou \xe9chapper \xe0 une cr\xe9ature qui l'agrippe). De plus, il b\xe9n\xe9ficie d'un bonus de +1 en DEF et en Initiative. Ce bonus passe \xe0 +2 au rang 3 et +3 au rang 5.",!1)
B.Kh=new A.t(2,"R\xe9flexes f\xe9lins","","Le voleur divise par 2 tous les DM de chute. De plus, une fois par combat, il obtient une action de mouvement suppl\xe9mentaire \xe0 son tour. Au rang 5, il peut r\xe9aliser cet exploit 2 fois par combat (mais pas plus d'une fois par round).",!1)
B.Jq=new A.t(3,"Acrobaties","G","Une fois par round, si le voleur r\xe9ussit un test d'AGI difficult\xe9 15, il peut effectuer une acrobatie pour franchir un obstacle (qui peut \xeatre un adversaire) ou attaquer de dos un adversaire au contact. Il peut alors au choix utiliser l'attaque sournoise ou infliger +1d4\xb0 DM.",!1)
B.Kr=new A.t(4,"Agilit\xe9 h\xe9ro\xefque","","Le voleur augmente sa valeur d'AGI de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests d'AGI.",!1)
B.JS=new A.t(5,"Esquive de la magie","G","Une fois par round, lorsqu'un sort qui inflige des DM physiques (feu, froid, projectile magique, etc.) le prend pour cible (y compris un sort de zone ou l'affectant en plus de la personne vis\xe9e), le voleur peut effectuer un test d'attaque \xe0 distance oppos\xe9 \xe0 un test d'attaque magique du lanceur sort. S'il r\xe9ussit, il \xe9chappe au sort. S'il \xe9choue, il subit les DM normaux.",!1)
B.a1J=A.a(s([B.Kg,B.Kh,B.Jq,B.Kr,B.JS]),t.P)
B.akR=new A.b5("voleur_voie-du-deplacement","Voie du D\xe9placement",B.a1J)
B.JK=new A.t(1,"Doigts agiles","","Le voleur ajoute son rang + 2 aux tests li\xe9s \xe0 la pr\xe9cision manuelle (crocheter une serrure, d\xe9samorcer un pi\xe8ge, pickpocket\u2026) ainsi qu'aux tests pour \xe9valuer un objet pr\xe9cieux (joyaux, bijoux, etc.). De plus il obtient +1 aux DM des attaques \xe0 distance avec les dagues et couteaux. Ce bonus passe \xe0 +2 au rang 3 de la voie et +3 au rang 5.",!1)
B.MW=new A.t(2,"Aux aguets","","Le voleur ajoute son rang + 2 aux tests effectu\xe9s pour fouiller une pi\xe8ce \xe0 la recherche d'un tr\xe9sor, d\xe9tecter un pi\xe8ge (m\xeame magique), un passage secret ou m\xeame une embuscade (Vigilance). De plus, il divise par 2 les DM inflig\xe9s par des pi\xe8ges.",!1)
B.L_=new A.t(3,"Feindre la mort","G","Une fois par combat, le voleur peut feindre la mort apr\xe8s avoir re\xe7u une blessure (m\xeame \xe0 0 PV). Il peut ainsi passer pour mort aussi longtemps qu'il le souhaite et un test d'INT difficult\xe9 20 est n\xe9cessaire pour r\xe9v\xe9ler la supercherie. Lorsqu'il d\xe9cide de se relever (action gratuite), le voleur r\xe9cup\xe8re imm\xe9diatement 1d4\xb0 PV et s'il est au contact d'un adversaire, celui-ci est surpris. Un adversaire qui a d\xe9j\xe0 \xe9t\xe9 victime de cette strat\xe9gie du voleur lors d'un pr\xe9c\xe9dent combat ne se laisse pas surprendre une seconde fois (sauf si son INT est de -4).",!1)
B.Nx=new A.t(4,"Expert en criminalit\xe9","","Le voleur obtient un d\xe9 bonus sur tous les tests de recherche d'indice (Trouver une preuve [PER], Faire une d\xe9duction [INT] et Obtenir un aveu [CHA]) ainsi que pour tous les tests r\xe9alis\xe9s pour brouiller des pistes, r\xe9aliser de faux indices ou de faux documents. De plus, lorsqu'il est dans un lieu, s'il d\xe9pense 1 PC, le MJ devra lui donner un indice qui lui a \xe9chapp\xe9 jusque-l\xe0. S'il n'y a pas d'indice, le PC n'est pas d\xe9pens\xe9.",!1)
B.KM=new A.t(5,"Ma\xeetre du poison","","Le voleur peut utiliser 3 doses de poison par jour sans risque de s'empoisonner lui-m\xeame. Une dose permet d'enduire une dague, une fl\xe8che ou un carreau pour infliger +2d4\xb0 DM suppl\xe9mentaire et demande un test de CON difficult\xe9 (10 + INT du voleur) ou une cible vivante est affaiblie pour le reste du combat. Alternativement, une dose peut \xeatre vers\xe9e dans les aliments pour une personne ; si la cible rate son test de CON, elle sombre dans l'inconscience pour 2d6 min (4d6 min pour 2 doses, etc.).",!1)
B.a0J=A.a(s([B.JK,B.MW,B.L_,B.Nx,B.KM]),t.P)
B.akN=new A.b5("voleur_voie-du-roublard","Voie du Roublard",B.a0J)
B.KA=new A.t(1,"Attaque en finesse","","Le voleur ajoute son AGI \xe0 son Init. et peut remplacer sa FOR par son AGI pour ses tests d'attaque au contact (mais pas aux DM) lorsqu'il utilise une arme l\xe9g\xe8re \xe0 une main (dague, \xe9p\xe9e courte ou rapi\xe8re). Enfin, il obtient un bonus \xe9gal \xe0 son rang + 2 aux tests d'intimidation.",!1)
B.Nd=new A.t(2,"Esquive fatale","G","Une fois par combat, le voleur peut esquiver une attaque et s'arranger pour que celle-ci affecte un autre adversaire \xe0 son contact. Comparez le test d'attaque \xe0 la DEF de la nouvelle cible pour savoir si celle-ci subit des DM. Cette capacit\xe9 ne peut pas \xeatre utilis\xe9e si le voleur n'a qu'un seul adversaire au contact et jamais contre une r\xe9ussite critique (un critique touche toujours sa cible).",!1)
B.MK=new A.t(3,"Frappe chirurgicale","","Par sa science de l'escrime (et de la fourberie), le voleur augmente ses chances de faire des coups critiques avec une arme l\xe9g\xe8re de 2 points (ainsi, au lieu de 20, le critique standard est obtenu entre 18 et 20). Toutefois, la valeur minimale requise pour obtenir un critique ne peut \xeatre inf\xe9rieure \xe0 16.",!1)
B.J1=new A.t(4,"Ambidextrie","G","Avec sa main gauche, le voleur peut effectuer une attaque au contact gratuite avec une dague ou une \xe9p\xe9e courte \xe0 chaque round. Cette attaque ne peut pas b\xe9n\xe9ficier des avantages d'une attaque sournoise.",!1)
B.Mg=new A.t(5,"Botte secr\xe8te","","Lorsque le voleur obtient un critique sur le d\xe9 d'une attaque au contact de sa main principale avec une arme l\xe9g\xe8re (mais pas sur une ouverture mortelle), il inflige \xe0 sa cible un \xe9tat pr\xe9judiciable au choix parmi affaibli, aveugl\xe9, \xe9tourdi, immobilis\xe9 ou ralenti pendant 1 round. Vous ne pouvez infliger chaque \xe9tat pr\xe9judiciable qu'une seule fois par combat. Alternativement, le voleur peut choisir que l'attaque devienne une attaque sournoise dont les DM s'ajoutent au critique (au lieu d'infliger un \xe9tat pr\xe9judiciable).",!1)
B.a2p=A.a(s([B.KA,B.Nd,B.MK,B.J1,B.Mg]),t.P)
B.alo=new A.b5("voleur_voie-du-spadassin","Voie du Spadassin",B.a2p)
B.a0u=A.a(s([B.akS,B.akK,B.akR,B.akN,B.alo]),t.oy)
B.LS=new A.t(1,"Argument de taille","","Le barbare ajoute sa FOR \xe0 son maximum de PV ainsi qu'\xe0 ses tests de CHA et \xe0 ceux de ses alli\xe9s au contact pour les tests de n\xe9gociation, de persuasion ou d'intimidation. Allez savoir pourquoi, sa simple pr\xe9sence donne de la force aux arguments de ses alli\xe9s\u2026",!1)
B.Nv=new A.t(2,"Tour de force","G","Le barbare peut temporairement d\xe9cupler ses ressources physiques pour faire usage d'une force prodigieuse. Il obtient un bonus de +10 sur un test de FOR (pas un jet de DM ou un test d'attaque), mais cela lui co\xfbte 1d4\xb0 PV (\xe0 d\xe9cider avant de lancer les d\xe9s). Enfin, le barbare peut d\xe9sormais porter une chemise de mailles et utiliser toutes les capacit\xe9s des voies de barbare auparavant autoris\xe9es avec une armure de cuir renforc\xe9.",!1)
B.O5=new A.t(3,"Attaque brutale","L","Le barbare effectue une puissante attaque au contact qui inflige +1d4\xb0 aux DM. \xc0 la place, il peut choisir de s'imposer un malus de -3 au test d'attaque pour obtenir +2d4\xb0 aux DM. Sur une attaque brutale r\xe9ussie, il peut sacrifier 1d4\xb0 DM pour faire reculer de 3 m un adversaire de NC inf\xe9rieur au rang atteint dans la voie, ou sacrifier 2d4\xb0 DM pour le renverser.",!1)
B.N6=new A.t(4,"Force h\xe9ro\xefque","","Le barbare augmente sa FOR de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de FOR.",!1)
B.Mn=new A.t(5,"Briseur d'os","","Le barbare augmente de 1 point les chances d'obtenir un critique sur les attaques au contact (par exemple 19-20 au lieu de 20). Lorsqu'il obtient un critique sur une attaque au contact, en plus des DM doubl\xe9s, la cible est \xe9tourdie pendant 1 round. Enfin, le barbare peut d\xe9sormais porter une cotte de mailles et utiliser toutes les capacit\xe9s des voies de barbare auparavant autoris\xe9es avec une chemise de mailles.",!1)
B.a2y=A.a(s([B.LS,B.Nv,B.O5,B.N6,B.Mn]),t.P)
B.alg=new A.b5("barbare_voie-de-la-brute","Voie de la Brute",B.a2y)
B.Nn=new A.t(1,"Cri de guerre","G","Une fois par combat, le barbare pousse un hurlement qui effraie ses adversaires dans un rayon de 10 m. Les adversaires dont la FOR est inf\xe9rieure \xe0 celle du barbare subissent un d\xe9 malus \xe0 leurs tests d'attaque au contact durant leur prochain tour. De plus, le barbare est sans peur, il ajoute son rang + 2 \xe0 tous les tests de VOL destin\xe9s \xe0 r\xe9sister \xe0 la peur.",!1)
B.Nt=new A.t(2,"D\xe9fier la mort","","Une fois par combat, lorsque le barbare subit des DM d'une attaque qui devrait l'amener \xe0 0 PV, il peut r\xe9aliser un test de CON difficult\xe9 10. En cas de r\xe9ussite, il conserve 1 PV. S'il est enrag\xe9, la r\xe9ussite est automatique.",!1)
B.KB=new A.t(3,"Rage du berserk","L","Une fois par jour, le barbare entre dans une rage berserk pour le reste du combat, ce qui le rend particuli\xe8rement dangereux. Il obtient +1d4\xb0 DM sur ses attaques au contact, mais il subit -2 en DEF et ne peut fuir de son propre gr\xe9 ou attaquer \xe0 distance. Enfin, il obtient un d\xe9 bonus pour tous les tests de VOL. S'il veut stopper la rage avant d'avoir \xe9limin\xe9 tous les ennemis sur le terrain, le barbare doit r\xe9ussir un test de VOL difficult\xe9 15 (un seul essai, \xe0 la fin de son tour). S'il devient inconscient, la rage cesse. Le personnage peut entrer en rage une fois de plus par jour pour chaque capacit\xe9 de rang 4 qu'il atteint dans une voie de barbare.",!1)
B.J4=new A.t(4,"M\xeame pas mal","","Une fois par combat, le barbare peut ignorer les DM d'un coup critique (il ne subit aucun DM) et il peut alors imm\xe9diatement entrer en Rage par une action gratuite.",!1)
B.IL=new A.t(5,"Furie du berserk","L","Au lieu de la Rage du berserk, le barbare peut entrer en Furie du berserk, mais cela consomme deux utilisations de la rage. Cet \xe9tat est similaire \xe0 la rage, mais le barbare ajoute 2d4\xb0 aux DM (au lieu de 1d4\xb0) et subit -4 en DEF. La difficult\xe9 du test pour mettre pr\xe9matur\xe9ment fin \xe0 la furie est \xe9gale \xe0 20.",!1)
B.a2B=A.a(s([B.Nn,B.Nt,B.KB,B.J4,B.IL]),t.P)
B.al0=new A.b5("barbare_voie-de-la-rage","Voie de la Rage",B.a2B)
B.MS=new A.t(1,"Vigueur","","Le barbare est un athl\xe8te capable de prouesses physiques extraordinaires, il ajoute son rang + 2 aux tests de course, de saut ou d'escalade. De plus, il gagne 1 PV suppl\xe9mentaire par rang atteint dans la voie.",!1)
B.J0=new A.t(2,"Peau de pierre","","Le barbare est particuli\xe8rement endurci, il encaisse les coups plut\xf4t que de les esquiver. Il peut choisir de remplacer son AGI par sa CON pour calculer sa DEF (la limitation du bonus maximal en fonction de l'armure port\xe9e s'applique toujours, mais cette fois elle s'applique \xe0 la CON). Autrement (si son AGI est sup\xe9rieure ou \xe9gale \xe0 sa CON), il re\xe7oit +1 en DEF et ce bonus passe \xe0 +2 au rang 4.",!1)
B.IR=new A.t(3,"Tatouages","","Le barbare poss\xe8de un tatouage magique* qui am\xe9liore ses performances physiques ou mentales. Au choix : Taureau (+3 aux tests de FOR), ours (+3 aux tests de CON), panth\xe8re (+3 aux tests d'AGI), chouette (+3 aux tests de PER), loup (+3 aux tests de CHA), renard (+3 aux tests d'INT) ou serpent (+3 aux tests de VOL). De plus, lorsqu'il subit l'\xe9tat \xe9tourdi, il est seulement ralenti. *Ce bonus n'est pas un bonus de comp\xe9tence, mais un bonus de magie qui ne peut donc pas se cumuler \xe0 un bonus fourni par un objet magique.",!1)
B.N1=new A.t(4,"Constitution h\xe9ro\xefque","","Le barbare augmente sa valeur de CON de +1 et obtient un d\xe9 bonus aux tests de CON.",!1)
B.Ml=new A.t(5,"Peau d'acier","","Le barbare ne sent plus la douleur et ignore les \xe9gratignures, il r\xe9duit tous les DM subis de 3 points (RD 3). Une attaque lui inflige toujours au minimum 1 DM.",!1)
B.a27=A.a(s([B.MS,B.J0,B.IR,B.N1,B.Ml]),t.P)
B.alL=new A.b5("barbare_voie-du-pagne","Voie du Pagne",B.a27)
B.Ma=new A.t(1,"R\xe9flexes \xe9clair","","Le barbare ajoute son rang + 2 \xe0 tous les tests d'AGI destin\xe9s \xe0 esquiver (Explosion de feu, souffle, pi\xe8ges, etc.). De plus, il gagne +3 en Init. et +1 en DEF. Le bonus de DEF passe \xe0 +2 au rang 5.",!1)
B.M8=new A.t(2,"Charge","L","Le barbare se d\xe9place en ligne droite entre 5 m et 10 m et effectue une attaque au contact avec un d\xe9 bonus et +1d4\xb0 aux DM. Il ne peut pas lancer une charge s'il est au contact d'un adversaire.",!1)
B.LK=new A.t(3,"Encha\xeenement","","Chaque fois que le barbare r\xe9duit un adversaire \xe0 0 PV avec une attaque de contact, il b\xe9n\xe9ficie d'une action d'attaque gratuite sur un autre adversaire \xe0 son contact. Encha\xeenement ne peut pas \xeatre cumul\xe9 \xe0 un d\xe9cha\xeenement d'acier ou une attaque tourbillon.",!1)
B.LQ=new A.t(4,"D\xe9cha\xeenement d'acier","L","Le barbare parcourt 10 m en ligne droite en d\xe9passant autant d'ennemis qu'il le souhaite. Il porte une attaque avec un malus de -2 \xe0 chaque adversaire sur son passage. Il doit traverser l'espace occup\xe9 par ceux-ci pour porter un coup, mais il ne peut terminer son d\xe9placement \xe0 un endroit occup\xe9 par un ennemi.",!1)
B.Kq=new A.t(5,"Attaque tourbillon","L","Une fois par combat, le barbare tourne sur lui-m\xeame en ass\xe9nant des attaques \xe0 toutes les cibles au contact. Il inflige automatiquement des DM correspondant \xe0 l'arme utilis\xe9e (plus tous les bonus habituels) \xe0 toutes les cibles dans un rayon de 5 m autour de lui.",!1)
B.a26=A.a(s([B.Ma,B.M8,B.LK,B.LQ,B.Kq]),t.P)
B.alt=new A.b5("barbare_voie-du-pourfendeur","Voie du Pourfendeur",B.a26)
B.KT=new A.t(1,"Proche de la nature","","Le barbare ajoute son rang + 2 \xe0 ses tests de survie (dont les tests de r\xe9cup\xe9ration) et de discr\xe9tion en milieu naturel. De plus, il gagne 1 PV suppl\xe9mentaire.",!1)
B.Lq=new A.t(2,"Armure de vent","","Lorsqu'il ne porte aucune armure, le barbare peut se relever par une action de mouvement et il obtient +2 en DEF. Ce bonus passe \xe0 +3 au rang 5. S'il porte une armure, il gagne seulement +1 en DEF.",!1)
B.MT=new A.t(3,"Vigilance","","Le barbare poss\xe8de des sens tr\xe8s aff\xfbt\xe9s, il est difficile de le surprendre, il ajoute son rang + 2 \xe0 tous les tests effectu\xe9s pour d\xe9tecter les pi\xe8ges m\xe9caniques, magiques (ses poils se h\xe9rissent) ou les embuscades. Il devient immunis\xe9 aux Attaques sournoises d'un voleur ou \xe0 toute capacit\xe9 similaire d'une cr\xe9ature de niveau inf\xe9rieur au sien.",!1)
B.NI=new A.t(4,"R\xe9sistance \xe0 la magie","G","Le barbare devient capable de r\xe9sister \xe0 la magie. Lorsqu'il est la cible d'un sort, une fois par round, il peut faire un test d'attaque magique* oppos\xe9 \xe0 celui du sort (si le sort n'en demande pas, faites-en tout de m\xeame un \xe0 cette occasion). En cas de r\xe9ussite, il n'en subit pas les effets. *Si le personnage est un profil hybride et qu'il est capable de faire de la magie (il poss\xe8de au moins une capacit\xe9 de sort), il subit un d\xe9 malus sur ce test oppos\xe9. Avoir c\xe9d\xe9 \xe0 la magie le rend moins apte \xe0 y r\xe9sister.",!1)
B.M4=new A.t(5,"Vitalit\xe9 d\xe9bordante","","Le barbare gu\xe9rit \xe0 une vitesse presque surnaturelle. Tant que son niveau actuel de PV est compris entre 1 et un tiers de son maximum, il r\xe9cup\xe8re 1d4\xb0 PV par heure, de nuit comme de jour.",!1)
B.a0d=A.a(s([B.KT,B.Lq,B.MT,B.NI,B.M4]),t.P)
B.akM=new A.b5("barbare_voie-du-primitif","Voie du Primitif",B.a0d)
B.a1h=A.a(s([B.alg,B.al0,B.alL,B.alt,B.akM]),t.oy)
B.Nb=new A.t(1,"Armure sur mesure","","L'armure du chevalier est parfaitement ajust\xe9e, aussi il n'ajoute que la moiti\xe9 de sa DEF \xe0 la difficult\xe9 des tests pour lesquels l'armure inflige une p\xe9nalit\xe9. De plus, lorsqu'il porte une armure lourde (plaque ou plaque compl\xe8te), il obtient un bonus de +1 en DEF \xe0 chaque fois qu'il atteint le rang 5 dans une voie de chevalier.",!1)
B.Ke=new A.t(2,"Encaisser un coup","M","Le chevalier se place de fa\xe7on \xe0 d\xe9vier un coup sur son armure. Jusqu'\xe0 son tour au round suivant, il peut retrancher la valeur de DEF de son armure (bonus de magie inclus si elle est enchant\xe9e) aux DM d'une seule attaque au contact qu'il subit (minimum 1 DM). Au rang 5, il peut ajouter son bonus de bouclier (cumulable au bonus d'armure). Le chevalier ne peut pas \xeatre \xe9tourdi ou renvers\xe9 par une attaque qu'il a d\xe9cid\xe9 d'encaisser.",!1)
B.MI=new A.t(3,"Frappe du justicier","L","Lorsque le chevalier r\xe9alise cette attaque au contact, si le test d'attaque est un \xe9chec, il inflige tout de m\xeame \xbd DM \xe0 sa cible. Un r\xe9sultat de 1 au d20 n'inflige aucun DM.",!1)
B.Nc=new A.t(4,"Force h\xe9ro\xefque","","Le chevalier augmente sa FOR de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de FOR.",!1)
B.JZ=new A.t(5,"Mon armure est une arme","G","Une fois par combat, le chevalier peut donner un coup avec son armure (gantelet, heaume, spalli\xe8re, etc.) en action gratuite. Il inflige automatiquement [1d4\xb0 + FOR] DM, et si la FOR de la cible est inf\xe9rieure \xe0 celle du chevalier, elle est (au choix du chevalier) renvers\xe9e ou \xe9tourdie pour 1 round ou recule de 3 m.",!1)
B.a0I=A.a(s([B.Nb,B.Ke,B.MI,B.Nc,B.JZ]),t.P)
B.alE=new A.b5("chevalier_voie-de-la-guerre","Voie de la Guerre",B.a0I)
B.MH=new A.t(1,"\xc9duqu\xe9","","Le chevalier sait lire et \xe9crire, et apprend \xe0 parler une langue suppl\xe9mentaire. De plus, il ajoute son rang + 2 \xe0 tous les tests d'histoire, d'h\xe9raldique et de g\xe9ographie ainsi qu'aux tests pour savoir se comporter dans la haute soci\xe9t\xe9.",!1)
B.IZ=new A.t(2,"\xc9cuyer","","Le chevalier dispose d'un \xe9cuyer \xe0 son service (Init. [chevalier], DEF [10 + rang], PV [niveau \xd7 4], Att [attaque magique], DM 1d4\xb0+1). Il est absolument loyal \xe0 son ma\xeetre, s'occupe de sa monture et de son \xe9quipement, pr\xe9pare le campement, panse les blessures, etc. Gr\xe2ce \xe0 l'\xe9cuyer, les armes du chevalier sont parfaitement aff\xfbt\xe9es et il augmente de 1 point les chances d'obtenir un critique sur les attaques au contact (par exemple, 19-20 au lieu de 20). De plus, le chevalier, sa monture et jusqu'\xe0 CHA alli\xe9s r\xe9cup\xe8rent 1d4\xb0 PV suppl\xe9mentaires apr\xe8s chaque r\xe9cup\xe9ration compl\xe8te s'ils profitent des services de l'\xe9cuyer. Si l'\xe9cuyer vient \xe0 mourir, le chevalier en prendra un autre \xe0 son service au niveau suivant.",!1)
B.Na=new A.t(3,"Autorit\xe9 naturelle","","Le chevalier ajoute son rang + 2 aux tests r\xe9alis\xe9s pour donner des ordres ou intimider. De plus, le noble chevalier re\xe7oit la formation n\xe9cessaire au port de l'armure de plaque compl\xe8te (DEF +7). D\xe9sormais, il peut utiliser toutes les capacit\xe9s des voies de chevalier en portant cette armure. Pour un profil hybride de combattant, cette capacit\xe9 permet d'augmenter le niveau d'armure d'un cran pour toutes les autres voies de combattant : jusqu'\xe0 l'armure de plaque pour les voies de guerrier et jusqu'\xe0 la chemise de mailles pour les voies de barbare.",!1)
B.NT=new A.t(4,"Massacrer la pi\xe9taille","","Le chevalier ajoute +1d4\xb0 aux DM contre la pi\xe9taille. S'il y a au moins 4 cr\xe9atures aux statistiques semblables impliqu\xe9es dans le combat, elles sont assimil\xe9es \xe0 de la pi\xe9taille (m\xeame si leur nombre est par la suite r\xe9duit \xe0 moins de 4 au cours du combat). Les cavaliers ne sont jamais consid\xe9r\xe9s comme de la pi\xe9taille.",!1)
B.JP=new A.t(5,"Formation d'\xe9lite","","Le chevalier poss\xe8de les moyens et la culture n\xe9cessaires pour obtenir une formation dans n'importe quel domaine qui lui sied. Choisissez une capacit\xe9 de rang 1 \xe0 3 dans n'importe quel profil issu de la famille des combattants ou des aventuriers. De plus, le chevalier choisit une caract\xe9ristique ; d\xe9sormais, il obtient un d\xe9 bonus lors des tests en rapport avec celle-ci.",!1)
B.a1a=A.a(s([B.MH,B.IZ,B.Na,B.NT,B.JP]),t.P)
B.akQ=new A.b5("chevalier_voie-de-la-noblesse","Voie de la Noblesse",B.a1a)
B.K0=new A.t(1,"Fid\xe8le monture","","Le chevalier poss\xe8de une fid\xe8le monture, un cheval de guerre bien dress\xe9 qui comprend les ordres simples. \xc0 cheval, il peut ajouter un d\xe9placement de 10 m avant ou apr\xe8s une action normale (par exemple, parcourir 10 m et r\xe9aliser une action limit\xe9e). La monture n'attaque que si elle est elle-m\xeame attaqu\xe9e au contact par une cr\xe9ature. De plus, le chevalier ajoute son rang + 2 aux tests d'\xe9quitation et de dressage. **Fid\xe8le monture :** AGI +0 | CON +4 | FOR +5 | PER +0 | CHA +0 | INT -2 | VOL +2 \u2014 DEF [12 + rang], PV [10 + Niveau \xd7 4], Init. [Init. du chevalier], Ruade +5, DM 1d4\xb0+5. La monture peut \xeatre soign\xe9e comme un personnage et elle r\xe9cup\xe8re 1d8+4 PV par nuit. Si la fid\xe8le monture meurt, le chevalier en r\xe9cup\xe8re une au niveau suivant.",!1)
B.Le=new A.t(2,"Cavalier \xe9m\xe9rite","","Lorsqu'il est en selle, le chevalier gagne un bonus de +1 aux DM de ses attaques au contact, et sa monture obtient une DEF \xe9gale \xe0 celle du chevalier. Monter ou descendre de cheval est d\xe9sormais une action gratuite. Le bonus aux DM passe \xe0 +2 au rang 5.",!1)
B.Ob=new A.t(3,"Charge","L","\xc0 cheval, le chevalier peut effectuer un d\xe9placement de 10 \xe0 20 m en ligne droite et faire une attaque de contact plac\xe9e au moment de son choix. Le joueur obtient un d\xe9 bonus au test d'attaque et ajoute 1d4\xb0 aux DM. Si une cr\xe9ature s'interpose pour bloquer la charge du chevalier, elle doit r\xe9ussir un test de FOR difficult\xe9 20 ou \xeatre contrainte de c\xe9der le passage en subissant 1d4\xb0 DM. Si elle r\xe9ussit ce test, la Charge est bloqu\xe9e et le tour du chevalier se termine.",!1)
B.JW=new A.t(4,"Monture magique","","Le chevalier obtient une monture magique, qui peut appara\xeetre et dispara\xeetre depuis un autre plan \xe0 volont\xe9. Il peut l'invoquer \xe0 tout moment (c'est une action limit\xe9e) et elle appara\xeet alors pour se mettre \xe0 son service. Lorsqu'il la laisse au moins une heure dans son plan d'origine, elle gu\xe9rit l'ensemble de ses PV.",!1)
B.LA=new A.t(5,"Monture fantastique","","Le chevalier obtient une monture puissante (cheval de guerre lourd, ours, f\xe9lin g\xe9ant, etc.). Init. [Init. du chevalier], DEF 20, PV [10 + niveau du chevalier \xd7 6], Ruade ou morsure [attaque magique], DM 2d4\xb0+5. Lorsqu'il est en selle, le chevalier peut faire attaquer sa monture une fois par round en action gratuite. \xc0 partir du niveau 9, le chevalier peut obtenir une monture volante (p\xe9gase, griffon, hippogriffe, etc.) si le MJ l'autorise. En vol, la monture couvre une distance de 20 m par action de mouvement, mais ses PV sont seulement \xe9gaux \xe0 [10 + niveau \xd7 5].",!1)
B.a_R=A.a(s([B.K0,B.Le,B.Ob,B.JW,B.LA]),t.P)
B.akG=new A.b5("chevalier_voie-du-cavalier","Voie du Cavalier",B.a_R)
B.Mj=new A.t(1,"Sans peur","","Le chevalier est immunis\xe9 aux effets de peur et il offre un bonus \xe9gal \xe0 son CHA aux tests de tous ses alli\xe9s contre ce type d'effet. De plus, le chevalier ajoute son rang + 2 aux tests de strat\xe9gie et de tactique militaire ou pour commander une troupe.",!1)
B.J8=new A.t(2,"Intercepter","G","Une fois par round, le chevalier peut encaisser une attaque au contact ou \xe0 distance \xe0 la place d'un alli\xe9 \xe0 son contact. Il utilise sa DEF plut\xf4t que celle de la cible initiale et retranche son rang dans la voie aux DM (en cas de synergie avec la capacit\xe9 Piq\xfbres d'insectes ou Encaisser un coup, la r\xe9duction des DM se cumule). Le joueur doit annoncer son intention d'intercepter avant de conna\xeetre le r\xe9sultat de l'attaque.",!1)
B.Ju=new A.t(3,"Exemplaire","G","Une fois par round, le chevalier donne un d\xe9 bonus \xe0 un alli\xe9 qui attaque un adversaire \xe0 son contact. Le d\xe9 bonus doit \xeatre attribu\xe9 avant de lancer les d\xe9s.",!1)
B.Kz=new A.t(4,"Charge fantastique","G","Une fois par combat, lorsque le chevalier d\xe9clare l'utilisation de cette capacit\xe9, tous ses alli\xe9s en vue et lui obtiennent 10 m de d\xe9placement suppl\xe9mentaire au d\xe9but de leur tour puis un d\xe9 bonus et +1d4\xb0 DM \xe0 toutes leurs attaques. Ne se cumule ni avec Exemplaire ni avec Ordre de bataille.",!1)
B.NC=new A.t(5,"Ordre de bataille","G","Le chevalier donne des ordres tactiques pertinents au c\u0153ur de la bataille. Une fois par round, il octroie une action suppl\xe9mentaire gratuite \xe0 un alli\xe9 en vue (une action de mouvement ou une action d'attaque, mais pas une action limit\xe9e). Chaque alli\xe9 ne peut profiter d'un ordre de bataille qu'une seule fois par combat.",!1)
B.a_N=A.a(s([B.Mj,B.J8,B.Ju,B.Kz,B.NC]),t.P)
B.alK=new A.b5("chevalier_voie-du-meneur-d-hommes","Voie du Meneur d'Hommes",B.a_N)
B.JM=new A.t(1,"Ignorer la douleur","G","Une fois par combat, le chevalier peut noter \xe0 part les DM subis par une attaque (mais pas un critique). Il ne subira les DM que lorsque le combat sera termin\xe9. De plus le h\xe9ros gagne un bonus \xe9gal \xe0 rang + 2 pour haranguer et convaincre les foules (au moins 15 individus).",!1)
B.M7=new A.t(2,"Piq\xfbres d'insectes","","Le chevalier obtient une r\xe9duction des DM (RD) des attaques \xe0 distance (arcs, arbal\xe8tes, lances, etc.) qui d\xe9pend de l'armure qu'il porte. Armure de plaques (compl\xe8te ou non) RD 3, armure interm\xe9diaire (chemise ou cotte de mailles) RD 2, armure de cuir (simple ou renforc\xe9e) RD 1. Les DM inflig\xe9s par une attaque sont toujours au minimum d'un point.",!1)
B.M5=new A.t(3,"Laissez-le-moi","","Le chevalier met un point d'honneur \xe0 combattre le leader ennemi. Lorsqu'il peut ais\xe9ment \xeatre identifi\xe9 dans un groupe d'au moins 4 cr\xe9atures, le chevalier lui inflige +1d4\xb0 DM par attaque au contact. Chaque fois que le chevalier inflige des DM \xe0 une cr\xe9ature de cette fa\xe7on, la cr\xe9ature doit r\xe9ussir un test d'INT difficult\xe9 15 ou elle ne peut pas attaquer d'autre adversaire que lui \xe0 son prochain tour.",!1)
B.J3=new A.t(4,"Charisme h\xe9ro\xefque","","Le chevalier augmente son CHA de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CHA.",!1)
B.Jd=new A.t(5,"Seul contre tous","","Le chevalier sait faire face \xe0 de nombreux adversaires. Lorsque au moins 3 adversaires l'attaquent au contact \xe0 ce round, il obtient une action d'attaque (A) suppl\xe9mentaire \xe0 ce round.",!1)
B.a2F=A.a(s([B.JM,B.M7,B.M5,B.J3,B.Jd]),t.P)
B.akH=new A.b5("chevalier_voie-du-preux","Voie du Preux",B.a2F)
B.a2d=A.a(s([B.alE,B.akQ,B.akG,B.alK,B.akH]),t.oy)
B.Ni=new A.t(1,"Robustesse","","Le guerrier augmente sa valeur maximale de PV de rang + 2. De plus, vous ajoutez votre rang + 2 \xe0 tous les tests destin\xe9s \xe0 r\xe9sister aux efforts physiques, \xe0 la chaleur ou au froid (conditions naturelles).",!1)
B.LP=new A.t(2,"R\xe9silient","","D\xe9sormais, il suffit de 10 min au guerrier pour b\xe9n\xe9ficier des effets d'une r\xe9cup\xe9ration rapide (au lieu de 30 min) et cela passe \xe0 5 min au rang 4 de la voie. De plus, le guerrier obtient un bonus \xe9gal au rang atteint dans la voie pour tous les tests destin\xe9s \xe0 r\xe9sister aux \xe9tats \xe9tourdi et affaibli.",!1)
B.Kn=new A.t(3,"Armure lourde","","Au choix le guerrier gagne +1 en DEF ou il apprend \xe0 porter l'armure de plaque (DEF +6) et d\xe9sormais, il peut utiliser toutes les capacit\xe9s de guerrier avec cette armure. Dans le cas d'un profil hybride, le personnage apprend \xe0 utiliser une armure d'une cat\xe9gorie au-dessus de celles autoris\xe9es par son profil principal. Par exemple, un barbare qui choisit cette capacit\xe9 peut d\xe9sormais entrer en rage en portant une chemise de mailles.",!1)
B.Lv=new A.t(4,"Constitution h\xe9ro\xefque","","Le guerrier augmente sa CON de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CON.",!1)
B.JD=new A.t(5,"Dur \xe0 cuire","","Le guerrier gagne +1 en DEF et, une fois par combat, lorsqu'il tombe \xe0 0 PV, il peut encore agir un round avant de tomber inconscient. De plus, il ne subit plus de d\xe9 malus lorsqu'il est immobilis\xe9 et lorsqu'il est \xe9tourdi ; il peut encore attaquer, mais avec un d\xe9 malus.",!1)
B.a2_=A.a(s([B.Ni,B.LP,B.Kn,B.Lv,B.JD]),t.P)
B.alk=new A.b5("guerrier_voie-de-la-resistance","Voie de la R\xe9sistance",B.a2_)
B.Ng=new A.t(1,"Prot\xe9ger un alli\xe9","G","S'il n'est pas surpris, le guerrier peut accorder un bonus de DEF de +2 \xe0 un alli\xe9 \xe0 son contact contre une attaque par round. Il doit annoncer son intention avant de conna\xeetre le r\xe9sultat de l'attaque. De plus, vous ajoutez votre rang + 2 \xe0 tous les tests destin\xe9s \xe0 \xe9viter d'\xeatre surpris.",!1)
B.O0=new A.t(2,"Parer un coup","M","Le guerrier utilise une action de mouvement pour se mettre en posture d\xe9fensive. Il peut alors essayer de parer une attaque \xe0 tout moment avant son prochain tour. Il doit faire un test d'attaque au contact (il peut remplacer la FOR par l'AGI pour ce test) en opposition au test de l'attaque au contact ou \xe0 distance r\xe9ussie par son adversaire. S'il l'emporte, l'attaque adverse est bloqu\xe9e par le bouclier. Il ne subit aucun DM sauf si la cr\xe9ature est de taille \xe9norme ou colossale, auquel cas, il subit tout de m\xeame la moiti\xe9 des DM. \xc0 partir du rang 5, le guerrier peut utiliser cette capacit\xe9 en action gratuite (toujours une fois par round), mais dans ce cas, il subit un d\xe9 malus au test oppos\xe9.",!1)
B.Kd=new A.t(3,"D\xe9fense au bouclier","","Le guerrier obtient un bonus de +1 en DEF lorsqu'il manie un bouclier. Ce bonus passe \xe0 +2 au rang 5. De plus, lorsqu'il tient son bouclier en main, il retranche son rang \xe0 tous les DM des attaques de zone (sorts d'Explosion de feu, mains br\xfblantes, foudre, etc. et aux souffles) sauf s'il est surpris.",!1)
B.Ko=new A.t(4,"Absorber un sort","","Lorsqu'il s'est pr\xe9par\xe9 \xe0 parer un coup, le guerrier peut d\xe9cider \xe0 la place d'absorber un sort. S'il r\xe9ussit un test d'attaque au contact (il peut remplacer la FOR par l'AGI pour ce test) oppos\xe9 \xe0 un test d'attaque magique du lanceur de sort, le sort est absorb\xe9 par le bouclier et n'a aucun effet sur le guerrier (mais s'il s'agit d'un sort de zone, les autres cibles sont affect\xe9es normalement).",!1)
B.Kw=new A.t(5,"Renvoi de sort","G","Le guerrier peut d\xe9cider de renvoyer un sort qu'il vient d'absorber gr\xe2ce \xe0 sa capacit\xe9 Absorber un sort. Au lieu d'\xeatre annul\xe9, le sort absorb\xe9 est imm\xe9diatement retourn\xe9 contre son exp\xe9diteur : le lanceur du sort subit alors les effets de sa propre attaque ! Cet effet ne fonctionne pas contre les sorts de zone.",!1)
B.a1Q=A.a(s([B.Ng,B.O0,B.Kd,B.Ko,B.Kw]),t.P)
B.akX=new A.b5("guerrier_voie-du-bouclier","Voie du Bouclier",B.a1Q)
B.Kf=new A.t(1,"Vivacit\xe9","","Le guerrier gagne +3 en Initiative et aux tests d'AGI ou de FOR pour \xe9viter d'\xeatre immobilis\xe9 ou renvers\xe9. De plus, une fois par combat, il obtient une action de mouvement suppl\xe9mentaire \xe0 son tour.",!1)
B.Je=new A.t(2,"Man\u0153uvre","","Le guerrier obtient un d\xe9 bonus lorsqu'il ex\xe9cute une man\u0153uvre en combat.",!1)
B.N8=new A.t(3,"Attaque puissante","","Le guerrier peut choisir de s'imposer un d\xe9 malus sur une attaque au contact et il ajoute +2d4\xb0 aux DM. Cette capacit\xe9 peut \xeatre utilis\xe9e avec Double attaque, Attaque circulaire ou Attaque parfaite. Transformez cette capacit\xe9 en action limit\xe9e (L) pour obtenir +3d4\xb0 aux DM au lieu de +2d4\xb0.",!1)
B.LH=new A.t(4,"Double attaque","L","Le guerrier fait deux attaques au contact durant son tour avec un malus de -2.",!1)
B.LZ=new A.t(5,"Attaque circulaire","L","Le guerrier peut faire une attaque au contact avec un malus de -2 contre chaque adversaire engag\xe9 au contact avec lui (il fait un test d'attaque pour chaque adversaire).",!1)
B.a1N=A.a(s([B.Kf,B.Je,B.N8,B.LH,B.LZ]),t.P)
B.akP=new A.b5("guerrier_voie-du-combat","Voie du Combat",B.a1N)
B.KY=new A.t(1,"Armes de pr\xe9dilection","","Le guerrier choisit une cat\xe9gorie d'armes de pr\xe9dilection parmi \xe9p\xe9es, haches, masses, lances (\xe9pieu, lance, pique) et enfin armes de jet (dague de lancer, javelot, etc.), et il gagne +1 en attaque lorsqu'il utilise une arme de cette cat\xe9gorie. De plus, vous ajoutez votre rang + 2 \xe0 tous les tests destin\xe9s \xe0 estimer la valeur d'une arme ou la r\xe9putation martiale d'un adversaire.",!1)
B.NF=new A.t(2,"Science du critique","","Le guerrier augmente de 1 point les chances d'obtenir un critique sur les attaques effectu\xe9es avec une arme de pr\xe9dilection (par exemple, 19-20 au lieu de 20).",!1)
B.JE=new A.t(3,"Sp\xe9cialisation","","Lorsque le guerrier emploie une arme de pr\xe9dilection, il gagne un bonus de +1 DM. Chaque fois que le personnage atteint le rang 5 dans une voie de guerrier, il peut choisir une nouvelle cat\xe9gorie d'arme de pr\xe9dilection (il gagne les avantages des rangs 1 \xe0 3) ou d\xe9cider d'augmenter de +1 le bonus aux DM d'une cat\xe9gorie qu'il conna\xeet d\xe9j\xe0 (pour un maximum de +6 pour un guerrier ayant atteint le rang 5 dans les cinq voies).",!1)
B.Od=new A.t(4,"Attaque parfaite","L","Vous obtenez un d\xe9 bonus en attaque au contact (ou \xe0 distance pour une arme de lancer) et ajoutez +1d4\xb0 DM. Vous devez utiliser une arme de pr\xe9dilection. \xc9ventuellement, le guerrier peut choisir de ne pas infliger les DM de son attaque parfaite pour d\xe9sarmer une cible dont le NC est inf\xe9rieur \xe0 son bonus de DM de sp\xe9cialisation.",!1)
B.LM=new A.t(5,"Riposte","G","Lorsqu'un adversaire rate une attaque de contact contre lui, le personnage obtient imm\xe9diatement une attaque au contact contre cet adversaire. Le personnage ne peut obtenir qu'une seule attaque suppl\xe9mentaire de cette fa\xe7on \xe0 chaque round et si plusieurs adversaires le ratent, il choisit contre lequel il effectue la riposte.",!1)
B.a2f=A.a(s([B.KY,B.NF,B.JE,B.Od,B.LM]),t.P)
B.alb=new A.b5("guerrier_voie-du-maitre-d-armes","Voie du Ma\xeetre d'Armes",B.a2f)
B.LU=new A.t(1,"Teigneux","G","Une fois par round, si une cr\xe9ature \xe0 votre contact tente de s'\xe9loigner de vous, vous obtenez une attaque au contact en action gratuite contre elle. De plus vous ajoutez votre rang + 2 aux tests destin\xe9s \xe0 r\xe9sister \xe0 l'alcool et \xe0 la privation de nourriture ou de sommeil.",!1)
B.Oc=new A.t(2,"Prouesse","G","Le guerrier r\xe9ussit souvent des exploits physiques hors-norme. Une fois par round, vous pouvez sacrifier 1d4\xb0 PV pour obtenir +5 sur un test de FOR ou de CON. Vous pouvez annoncer l'utilisation de cette capacit\xe9 apr\xe8s avoir pris connaissance du r\xe9sultat du test de caract\xe9ristique.",!1)
B.Mb=new A.t(3,"Piq\xfbre de rappel","G","Vous n'admettez pas qu'un adversaire vous ignore. Une fois par round, si un adversaire \xe0 votre contact attaque une autre cr\xe9ature que vous, vous obtenez une attaque en action gratuite contre lui. Si l'INT de cet adversaire est n\xe9gative et que vous lui infligez des DM sur cette attaque, il vous prend automatiquement pour cible lors de sa prochaine attaque.",!1)
B.LG=new A.t(4,"Force h\xe9ro\xefque","","Le guerrier augmente sa FOR de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de FOR.",!1)
B.LV=new A.t(5,"Rempart","","Vous pouvez d\xe9sormais utiliser Teigneux contre un nombre d'adversaires \xe9gal \xe0 votre AGI + 2 \xe0 chaque round. Si vous r\xe9ussissez cette attaque, le d\xe9placement de votre adversaire est stopp\xe9 \xe0 l'endroit o\xf9 vous l'avez attaqu\xe9. De plus vous gagnez +1 en DEF.",!1)
B.a28=A.a(s([B.LU,B.Oc,B.Mb,B.LG,B.LV]),t.P)
B.akJ=new A.b5("guerrier_voie-du-soldat","Voie du Soldat",B.a28)
B.a25=A.a(s([B.alk,B.akX,B.akP,B.alb,B.akJ]),t.oy)
B.L9=new A.t(1,"Murmures dans le vent","G","L'ensorceleur chuchote un message d'une dizaine de mots qui voyage jusqu'\xe0 son destinataire. Il peut entendre sa r\xe9ponse imm\xe9diatement. La port\xe9e est de CHA \xd7 100 m et le personnage doit conna\xeetre la cible ou la voir. En plus de ce sort, l'ensorceleur gagne un bonus permanent de +1 en Init. et en DEF, car parfois une bourrasque venue de nulle part vient g\xeaner son attaquant, d\xe9vier un projectile ou lui permettre d'entendre un adversaire.",!0)
B.Np=new A.t(2,"Sous tension","M","L'ensorceleur se charge d'\xe9nergie \xe9lectrique pour CHA minutes. Pendant toute la dur\xe9e du sort, une cr\xe9ature qui le blesse par une attaque de contact ou le touche re\xe7oit une d\xe9charge infligeant 1d4\xb0 DM. De plus, il peut utiliser une action d'attaque \xe0 chaque round pour d\xe9livrer une d\xe9charge \xe9lectrique (test d'attaque magique contre DEF de la cible, port\xe9e 10 m) infligeant [1d4\xb0+CHA] DM.",!0)
B.JB=new A.t(3,"T\xe9l\xe9kin\xe9sie","A","L'ensorceleur peut d\xe9placer dans les airs un objet inerte (qui n'est pas tenu par un adversaire) ou une cible volontaire (par exemple lui-m\xeame) dont le poids n'exc\xe8de pas 50 kg par rang, \xe0 une port\xe9e de 20 m et pendant CHA minutes. L'objet peut \xeatre maintenu en l'air ou d\xe9plac\xe9 de 5 m par action de mouvement. Il est possible de faire tomber un objet sur une cible surprise (test d'attaque magique, DM 1d6 par tranche de 50 kg).",!0)
B.Kb=new A.t(4,"Foudre","A","L'ensorceleur produit un \xe9clair sur une ligne de 10 m. Toutes les cr\xe9atures sur la trajectoire subissent [4d4\xb0+CHA] DM ou seulement la moiti\xe9 pour celles qui r\xe9ussissent un test d'AGI difficult\xe9 [10 + CHA].",!0)
B.NM=new A.t(5,"Forme \xe9th\xe9r\xe9e","L","L'ensorceleur et tout son \xe9quipement deviennent translucides et intangibles pendant CHA minutes. Sous cette forme, il peut passer \xe0 travers murs et obstacles et ne peut subir aucun DM physiques (m\xeame inflig\xe9s par une arme magique), ni en infliger, ni lancer de sorts. Il n'est pas affect\xe9 par la gravit\xe9 et peut se d\xe9placer dans toutes les directions. Il est stopp\xe9 par les barri\xe8res magiques et ne peut pas passer \xe0 travers les \xeatres vivants.",!0)
B.a0b=A.a(s([B.L9,B.Np,B.JB,B.Kb,B.NM]),t.P)
B.ala=new A.b5("ensorceleur_voie-de-l-air","Voie de l'Air",B.a0b)
B.IU=new A.t(1,"Injonction","A","L'ensorceleur donne un ordre simple (mais pas suicidaire) de deux ou trois mots que la cible doit pouvoir comprendre. S'il r\xe9ussit un test oppos\xe9 d'attaque magique contre une cible \xe0 une port\xe9e de 20 m, la victime doit ex\xe9cuter l'ordre pendant son prochain tour. En plus de ce sort, l'ensorceleur ajoute son rang + 2 aux tests de persuasion ou de s\xe9duction.",!0)
B.Jr=new A.t(2,"Sommeil","L","Une fois par combat, l'ensorceleur vise une zone de 10 m de diam\xe8tre \xe0 une port\xe9e maximale de 20 m. Le sort affecte jusqu'\xe0 [1d4\xb0 + CHA] cr\xe9atures vivantes de NC inf\xe9rieur \xe0 1. Le sort affecte les cr\xe9atures de NC inf\xe9rieur \xe0 2 au rang 4 puis \xe0 3 au rang 5. Les cr\xe9atures perdent conscience pendant CHA minutes. Il est possible de les r\xe9veiller en les cognant violemment (action d'attaque, 1 DM).",!0)
B.ML=new A.t(3,"Confusion","A","En r\xe9ussissant un test oppos\xe9 d'attaque magique contre sa cible (port\xe9e 20 m), l'ensorceleur d\xe9soriente sa victime pendant CHA rounds. Au tour de la victime, celui qui l'incarne lance 1d6 : sur 1-3 la victime n'agit pas, sur 4-6 elle attaque la cr\xe9ature la plus proche (au hasard). \xc0 la fin de son tour, elle peut mettre fin au sort pr\xe9matur\xe9ment en r\xe9ussissant un test de VOL difficult\xe9 [12 + CHA de l'ensorceleur].",!0)
B.L3=new A.t(4,"Amiti\xe9","L","Si l'ensorceleur r\xe9ussit un test oppos\xe9 d'attaque magique (port\xe9e 10 m) contre une cible humano\xefde de niveau ou NC inf\xe9rieur au sien, celle-ci se comporte comme un ami de longue date tant qu'elle n'est pas attaqu\xe9e. La victime peut r\xe9sister au sort avec un test de VOL difficult\xe9 [10 + CHA de l'ensorceleur] une fois par jour apr\xe8s chaque r\xe9cup\xe9ration compl\xe8te. Si la cible est d'un niveau au moins \xe9gal au niveau du lanceur de sort, ce dernier obtient seulement un d\xe9 bonus \xe0 tous les tests de CHA qu'il effectue contre la victime pendant 10 min.",!0)
B.Ja=new A.t(5,"Domination","A","En r\xe9ussissant un test oppos\xe9 d'attaque magique contre une cible de niveau ou NC inf\xe9rieur au sien (port\xe9e 20 m), l'ensorceleur prend contr\xf4le de sa cible pendant CHA minutes. Son propre corps devient inactif et s'\xe9croule au sol. Si la cr\xe9ature meurt pendant la domination, l'ensorceleur r\xe9int\xe8gre son corps et subit 1d4\xb0 DM. Si la cible est d'un niveau trop \xe9lev\xe9, il peut la forcer \xe0 faire une seule action de son choix (mouvement ou attaque); ensuite, il est \xe9ject\xe9 et subit 1d4\xb0 DM.",!0)
B.a2H=A.a(s([B.IU,B.Jr,B.ML,B.L3,B.Ja]),t.P)
B.alc=new A.b5("ensorceleur_voie-de-l-envouteur","Voie de l'Envo\xfbteur",B.a2H)
B.Me=new A.t(1,"Choc","A","Si l'ensorceleur r\xe9ussit un test d'attaque magique r\xe9ussi contre la DEF de son adversaire situ\xe9 \xe0 une port\xe9e de 20 m, il lui inflige [1d4\xb0 + CHA] DM. Si la cible a un NC inf\xe9rieur au rang atteint par l'ensorceleur dans la voie, elle doit r\xe9ussir un test de FOR difficult\xe9 10 pour ne pas \xeatre renvers\xe9e.",!0)
B.KC=new A.t(2,"Serviteur invisible","L","Ce sort cr\xe9e une force invisible pendant CHA minutes. Le serviteur peut effectuer \xe0 distance des t\xe2ches simples ne n\xe9cessitant pas de test de r\xe9ussite avec une AGI et une INT de +0 et une FOR \xe9gale au CHA de l'ensorceleur (port\xe9e 20 m). Il peut par exemple rapporter un objet ou actionner un levier, voire faire la vaisselle. Le serviteur invisible se d\xe9place \xe0 la m\xeame vitesse que l'ensorceleur, ne p\xe8se rien, ne parle pas, n'a pas vraiment d'existence et peut se d\xe9placer dans toutes les directions. Concevez-le davantage comme une force qui ob\xe9it aux injonctions t\xe9l\xe9pathiques de son cr\xe9ateur que comme une cr\xe9ature. Il n'attaque pas et ne peut pas \xeatre combattu, mais il peut \xeatre dissip\xe9 gr\xe2ce au sort de ma\xeetrise de la magie.",!0)
B.Lt=new A.t(3,"Arme de mana","A","Le sort cr\xe9e une lame d'\xe9nergie lumineuse pendant [rang] rounds. D\xe8s le premier round et \xe0 chaque round suivant, l'ensorceleur peut lui ordonner d'attaquer une cible de son choix \xe0 port\xe9e (action gratuite, port\xe9e 20 m). La lame doit r\xe9ussir un test d'attaque magique contre la DEF de l'adversaire. Elle inflige [1d4\xb0 + CHA] DM en cas de r\xe9ussite. L'ensorceleur ne peut maintenir actif qu'un seul sort d'arme de mana \xe0 la fois.",!0)
B.O6=new A.t(4,"Porte dimensionnelle","A","L'ensorceleur se t\xe9l\xe9porte lui-m\xeame et jusqu'\xe0 un alli\xe9 par point de CHA \xe0 une distance maximale de 60 m. Le lieu d'arriv\xe9e doit \xeatre en vue.",!0)
B.JU=new A.t(5,"Mur de mana","A","L'ensorceleur cr\xe9e un mur de force invisible et indestructible (port\xe9e 10 m, maximum 5 m de haut et 10 m de long, vertical, sans coudes), ou bien un h\xe9misph\xe8re de 3 m de rayon centr\xe9 sur lui-m\xeame, tous les deux immobiles. Le sort dure CHA minutes. Aucune mati\xe8re ni force ne peut passer \xe0 travers le mur de force. En revanche, les attaques mentales ne sont pas stopp\xe9es et une porte dimensionnelle (ou une t\xe9l\xe9portation) permet de le franchir.",!0)
B.a_E=A.a(s([B.Me,B.KC,B.Lt,B.O6,B.JU]),t.P)
B.akZ=new A.b5("ensorceleur_voie-de-l-invocation","Voie de l'Invocation",B.a_E)
B.Jz=new A.t(1,"Divination","L","S'il emporte un test oppos\xe9 d'attaque magique contre une cr\xe9ature de NC inf\xe9rieur \xe0 son niveau (port\xe9e 10 m), l'ensorceleur devine son nom d'usage, son m\xe9tier et quelques autres renseignements, tous de notori\xe9t\xe9 publique (si la cible agit sous couverture, ce sont les informations qui concernent la couverture que l'ensorceleur apprend). Si la cible du sort est volontaire et qu'il lit les lignes de sa main, il n'y a pas besoin de test et l'ensorceleur peut utiliser ce sort sur une cr\xe9ature de NC sup\xe9rieur ou \xe9gal \xe0 son niveau. En plus de ce sort, l'ensorceleur gagne +1 en Init. et en DEF. Ce bonus augmente de +1 au rang 3 de la voie et de +1 chaque fois que le personnage atteint le rang 5 dans une voie d'ensorceleur.",!0)
B.Lu=new A.t(2,"D\xe9tection de l'invisible","L","Pendant CHA minutes, l'ensorceleur d\xe9tecte les cr\xe9atures invisibles (le sort r\xe9v\xe8le une silhouette, mais pas l'apparence exacte de la cr\xe9ature) ou cach\xe9es \xe0 moins de 20 m et si un sort de Clairvoyance affecte l'endroit. Aveugl\xe9 (par magie ou dans l'obscurit\xe9), ce sort lui permet de d\xe9tecter les cr\xe9atures pr\xe9sentes (et donc d'attaquer sans malus), mais pas de distinguer son environnement.",!0)
B.Mi=new A.t(3,"Clairvoyance","A","L'ensorceleur peut voir et entendre \xe0 distance ce qui se passe dans un lieu qu'il conna\xeet (pas de limite de port\xe9e) ou juste derri\xe8re une porte qu'il touche pendant CHA rounds (action limit\xe9e \xe0 chaque round). Les cr\xe9atures pr\xe9sentes ont droit \xe0 un test de PER difficult\xe9 [12 + CHA de l'ensorceleur] : en cas de r\xe9ussite, elles se sentent observ\xe9es.",!0)
B.Nw=new A.t(4,"Perception h\xe9ro\xefque","","L'ensorceleur augmente sa valeur de PER de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de PER, et il ajoute sa PER au nombre de PM dont il b\xe9n\xe9ficie.",!1)
B.Ld=new A.t(5,"Prescience","","Une fois par combat, au d\xe9but du round, le joueur peut d\xe9cider qu'il a eu une vision des diff\xe9rents futurs possibles. Il b\xe9n\xe9ficie d'un bonus de +10 en attaque, en D\xe9fense et \xe0 tous les tests de PER pour tout le round, il divise tous les DM subis par 2 et il peut choisir d'agir \xe0 n'importe quel moment dans le round, sans consid\xe9ration d'initiative.",!1)
B.a1n=A.a(s([B.Jz,B.Lu,B.Mi,B.Nw,B.Ld]),t.P)
B.alh=new A.b5("ensorceleur_voie-de-la-divination","Voie de la Divination",B.a1n)
B.KV=new A.t(1,"Mirage","L","L'ensorceleur cr\xe9e une illusion visuelle et sonore immobile d'une dur\xe9e de CHA minutes. Le volume maximal de l'illusion est de 2 m de c\xf4t\xe9 par rang dans la voie (port\xe9e 50 m). \xc0 partir du rang 4, l'illusion peut \xeatre anim\xe9e, mais dans ce cas sa dur\xe9e est exprim\xe9e en rounds. En plus de ce sort, l'ensorceleur ajoute son rang + 2 aux tests de supercherie ou \xe0 tout test qui lui servirait \xe0 mentir.",!0)
B.Mv=new A.t(2,"Image d\xe9cal\xe9e","M","L'ensorceleur cr\xe9e des images d\xe9cal\xe9es qui se superposent \xe0 sa silhouette pendant [1d4 + CHA] rounds. Lorsqu'une attaque au contact ou \xe0 distance le touche, l'ensorceleur lance 1d6 : sur 5-6, il ne subit pas les DM.",!0)
B.MC=new A.t(3,"Sort illusoire","A","L'ensorceleur lance un sort d'attaque qui n'est qu'une illusion. Il inflige [3d4\xb0+CHA] DM contre une seule cible ou [2d4\xb0+CHA] DM contre un maximum de cibles \xe9gal au rang atteint. Le joueur peut d\xe9crire la nature du sort \xe0 sa guise (une Explosion de feu, une nu\xe9e de criquets, une lance de glace, etc.), son imagination demeurant sa seule limite. Chaque cible peut faire un test de PER difficult\xe9 [10 + CHA de l'ensorceleur] pour ne subir aucun DM. Les cr\xe9atures sans esprit (cr\xe9atures artificielles, certaines plantes et morts-vivants) sont immunis\xe9es \xe0 ce sort. Les PV perdus de cette fa\xe7on se r\xe9cup\xe8rent normalement.",!0)
B.Jv=new A.t(4,"Imitation","A","Pendant CHA minutes, l'ensorceleur peut prendre l'apparence d'une cr\xe9ature de taille proche de la sienne (+ ou - 50 cm) qu'il voit au moment de l'incantation. Une cr\xe9ature qui touche l'ensorceleur se rend compte que quelque chose ne va pas et a le droit \xe0 un test d'INT difficult\xe9 [10 + CHA de l'ensorceleur] pour voir \xe0 travers l'illusion.",!0)
B.IX=new A.t(5,"Ex\xe9cution mentale","A","Ce sort invoque les pires terreurs d'une cr\xe9ature humano\xefde vivante et lui fait croire \xe0 sa propre mort. L'ensorceleur doit faire un test oppos\xe9 d'attaque magique contre sa cible (port\xe9e 20 m). En cas de succ\xe8s la victime tombe \xe0 0 PV ou si la cible est de niveau sup\xe9rieur ou \xe9gal \xe0 l'ensorceleur, elle est \xe9tourdie (-5 DEF et pas d'action) pendant 1 round. Une cr\xe9ature ne peut \xeatre la cible de ce sort qu'une fois par jour. Les cr\xe9atures sans esprit (cr\xe9atures artificielles, certaines plantes et certains morts-vivants) sont immunis\xe9es \xe0 ce sort.",!0)
B.a1I=A.a(s([B.KV,B.Mv,B.MC,B.Jv,B.IX]),t.P)
B.alx=new A.b5("ensorceleur_voie-des-illusions","Voie des Illusions",B.a1I)
B.a2G=A.a(s([B.ala,B.alc,B.akZ,B.alh,B.alx]),t.oy)
B.O3=new A.t(1,"B\xe2ton de mage","","Lorsqu'il utilise son b\xe2ton, le forgesort inflige [1d4\xb0+INT] DM magiques. \xc0 partir du rang 3, au prix d'une action limit\xe9e, il peut utiliser sa valeur d'attaque magique pour une attaque au contact et il inflige [2d4\xb0+INT] DM dans un \xe9clair d'\xe9nergie! Si le forgesort fait l'acquisition d'un b\xe2ton magique, les bonus de celui-ci s'ajouteront normalement \xe0 l'attaque et aux DM (de m\xeame pour le bonus de feu de la voie du m\xe9tal).",!1)
B.Lz=new A.t(2,"Ouverture - fermeture","M","Le forgesort peut ouvrir une porte ferm\xe9e \xe0 clef en la touchant, il doit r\xe9ussir un test d'attaque magique contre la difficult\xe9 pour la crocheter. Il peut aussi sceller une porte ou un coffre pour INT minutes. Seul un mot de commande qu'il choisit permet d'ouvrir l'objet. Celui-ci peut toujours \xeatre bris\xe9 par la force, mais il b\xe9n\xe9ficie d'un bonus de +5 en solidit\xe9 et en RD pour toute la dur\xe9e du sort. \xc0 partir du rang 4, le forgesort peut rendre ce sort permanent en sacrifiant une gemme d'une valeur de 100 pa et en prolongeant l'incantation par un rituel de 10 min.",!0)
B.O_=new A.t(3,"Sac sans fond","","Le forgesort poss\xe8de un sac magique dans lequel il peut entreposer 50 kg de mat\xe9riel par rang dans la voie, tandis que le sac semble toujours peser un kilogramme. Le sac ne fonctionne pas si on tente d'y mettre une cr\xe9ature vivante. Le sac est de plus capable de fournir au forgesort les objets qu'il d\xe9sire. Une fois par heure, il peut en retirer un ou plusieurs objets dont la valeur totale ne d\xe9passe pas 25 pa, le poids 50 kg, la circonf\xe9rence 1 m et le volume 1 m3. Ces objets ont h\xe9las la propri\xe9t\xe9 de dispara\xeetre au bout d'une heure. De ce fait, la nourriture magique retir\xe9e du sac ne nourrit pas vraiment celui qui la consomme.",!1)
B.Mo=new A.t(4,"Frappe des arcanes","A","Le forgesort frappe le sol de son b\xe2ton et provoque une onde d\xe9vastatrice dans un rayon de 10 m autour de lui. Toutes les cr\xe9atures dans la zone subissent automatiquement [3d4\xb0+INT] DM et doivent r\xe9ussir un test de FOR difficult\xe9 [10 + INT] pour ne pas \xeatre renvers\xe9es.",!0)
B.Mx=new A.t(5,"Artefact \xe9trange","L","Le forgesort cr\xe9e un artefact qu'il est le seul \xe0 pouvoir utiliser et dont la description est laiss\xe9e au soin du joueur. L'artefact permet d'utiliser les capacit\xe9s de rang 5 suivantes chacune une fois par jour au prix d'une action limit\xe9e : T\xe9l\xe9portation (voie de la magie universelle, magicien), Interruption du temps (voie de la magie protectrice, magicien), Forme \xe9th\xe9r\xe9e (voie de l'air, ensorceleur), Prescience (voie de la divination, ensorceleur). \xc0 chaque utilisation, le joueur doit lancer 1d6 : sur un r\xe9sultat de 1 ou 2, l'artefact ne fonctionne pas, le forgesort doit r\xe9parer l'artefact lors d'une r\xe9cup\xe9ration rapide avant de pouvoir faire une nouvelle tentative de ce pouvoir (il peut tenter d'utiliser les autres pouvoirs normalement).",!1)
B.a_x=A.a(s([B.O3,B.Lz,B.O_,B.Mo,B.Mx]),t.P)
B.aly=new A.b5("forgesort_voie-des-artefacts","Voie des Artefacts",B.a_x)
B.Oh=new A.t(1,"Fortifiant","L","Un breuvage qui gu\xe9rit imm\xe9diatement 1d4\xb0 PV et permet de gagner un d\xe9 bonus aux trois prochains tests effectu\xe9s dans une p\xe9riode de 30 min. En plus de cette recette, gr\xe2ce \xe0 ses \xe9tudes, le forgesort ajoute son rang + 2 aux tests d'alchimie et de chimie ou pour identifier une potion (test difficult\xe9 10 + rang du sort).",!1)
B.ND=new A.t(2,"Feu gr\xe9geois","L","Le forgesort lance la fiole \xe0 une distance maximale de 10 m (r\xe9ussite automatique). Le contenu explose dans un rayon de 3 m en infligeant 2d4\xb0 DM. Un test d'AGI difficult\xe9 [10 + INT du forgesort] r\xe9ussi permet aux victimes de diviser les DM par deux. Les DM passent \xe0 3d4\xb0 au rang 4 et 4d4\xb0 au rang 5.",!1)
B.N_=new A.t(3,"\xc9lixir de gu\xe9rison","L","Le forgesort peut pr\xe9parer un \xe9lixir qui soigne [2d4\xb0+INT] PV au bout d'une minute ou gu\xe9rit un empoisonnement de mani\xe8re instantan\xe9e.",!1)
B.IY=new A.t(4,"\xc9lixirs mineurs","L","Le forgesort apprend \xe0 pr\xe9parer des \xe9lixirs parmi Forme gazeuse, Ma\xeetrise des \xe9l\xe9ments, Chute ralentie (voies de magicien) et Masque mortuaire (voie de sorcier). Il choisit un nombre d'\xe9lixirs \xe9gal \xe0 sa valeur d'INT (pour un maximum de 4).",!1)
B.NY=new A.t(5,"\xc9lixirs majeurs","L","Le forgesort apprend \xe0 pr\xe9parer des \xe9lixirs parmi Invisibilit\xe9, Vol, Acc\xe9l\xe9ration (voies de magicien) et Masque du pr\xe9dateur (voie de druide). Il choisit un nombre d'\xe9lixirs \xe9gal \xe0 sa valeur d'INT (pour un maximum de 4). Ces pr\xe9parations comptent pour deux \xe9lixirs. Note : si un personnage choisit une capacit\xe9 issue de la voie des \xe9lixirs par l'interm\xe9diaire d'une autre voie, il acquiert seulement deux \xe9lixirs par jour (ou un seul dans le cas d'un \xe9lixir majeur). Consommer un \xe9lixir n'est pas limit\xe9 par le type d'armure que porte celui qui le boit.",!1)
B.a1p=A.a(s([B.Oh,B.ND,B.N_,B.IY,B.NY]),t.P)
B.alu=new A.b5("forgesort_voie-des-elixirs","Voie des \xc9lixirs",B.a1p)
B.NQ=new A.t(1,"Runes de d\xe9fense","","Le forgesort inscrit des runes de protection sur l'ensemble de son \xe9quipement et parfois jusque sur sa peau. Il obtient un bonus de +2 en DEF. Ce bonus augmente de +1 au rang 3 puis au rang 5. S'il poss\xe8de un golem, il peut inscrire les runes sur celui-ci avec le m\xeame effet. PROFIL HYBRIDE Exceptionnellement, un profil hybride peut utiliser cette capacit\xe9 avec une armure qu'il est capable de porter, sup\xe9rieure \xe0 l'armure de cuir, bien que, dans ce cas, le bonus de DEF soit alors divis\xe9 par deux (+1 en DEF au rang 1, +2 au rang 4). Bien que cette capacit\xe9 ne soit pas consid\xe9r\xe9e comme un sort, elle requiert au moins +1 en INT pour \xeatre apprise, comme toutes les runes de forgesort.",!1)
B.K5=new A.t(2,"Rune de puissance","L","Le forgesort enchante une arme pour 24 h. Une fois par combat, celle-ci peut d'infliger les DM maximaux sur une attaque au contact ou \xe0 distance. Les d\xe9s bonus ne sont pas maximis\xe9s (attaque sournoise ou puissante, rage, etc.). Le joueur doit annoncer l'utilisation de la rune avant de lancer les d\xe9s de DM.",!0)
B.L5=new A.t(3,"Rune de protection","A","Le forgesort enchante une armure (ou des v\xeatements) pour 24 h. Une fois par jour, celle-ci permet d'ignorer les dommages d'une attaque que le personnage subit (au contact, magique ou \xe0 distance). Si l'attaque est un critique, le personnage subit tout de m\xeame les DM normaux (non-critique). Pour activer la rune, le personnage doit \xeatre conscient et ne pas \xeatre surpris (action gratuite). Le joueur doit activer la rune avant de conna\xeetre le montant des DM.",!0)
B.N5=new A.t(4,"Rune d'\xe9nergie","A","Le forgesort enchante un bijou pour une dur\xe9e de 24 h. Une fois par combat, celui-ci permet d'obtenir un d20 bonus sur un test de son choix d\xe9termin\xe9 au moment o\xf9 l'effet est utilis\xe9 : test d'attaque ou de caract\xe9ristique.",!0)
B.MZ=new A.t(5,"Rune de garde","","En r\xe9alisant un rituel de 10 min, le forgesort inscrit des runes invisibles au sol. Il prot\xe8ge une zone allant jusqu'\xe0 10 m de diam\xe8tre pendant 12 h. \xc0 chaque fois qu'une cr\xe9ature (de taille au moins tr\xe8s petite) p\xe9n\xe8tre dans la zone prot\xe9g\xe9e, le sort produit un effet choisi (voir ci-apr\xe8s) au moment o\xf9 le sort est lanc\xe9. Les cr\xe9atures pr\xe9sentes dans la zone pendant le rituel ne d\xe9clenchent pas le sort. Ce sort peut aussi \xeatre utilis\xe9 sur une porte ou un coffre. Il est automatiquement lanc\xe9 avec la r\xe8gle de concentration et co\xfbte seulement 3 PM pour \xeatre lanc\xe9. Alarme : un puissant gong retentit et la cible est \xe9tourdie pendant 1 round \xe0 moins de r\xe9ussir un test de CON difficult\xe9 15. Feu : [3d4\xb0+INT] DM de feu (un autre \xe9l\xe9ment peut \xeatre choisi parmi foudre, froid, acide).",!0)
B.a_z=A.a(s([B.NQ,B.K5,B.L5,B.N5,B.MZ]),t.P)
B.alJ=new A.b5("forgesort_voie-des-runes","Voie des Runes",B.a_z)
B.N7=new A.t(1,"Grosse t\xeate","","Le forgesort remplace la force brutale par un peu de r\xe9flexion. Il peut effectuer un test d'INT au lieu d'un test de FOR (par exemple, il utilise un levier pour d\xe9placer une lourde charge). De plus, au premier niveau, il peut ajouter son INT \xe0 ses PV \xe0 la place de sa CON s'il le souhaite. Il ajoute son rang + 2 \xe0 tous les tests de bricolage ou de science.",!1)
B.LR=new A.t(2,"Golem","","Le golem est une cr\xe9ature humano\xefde fabriqu\xe9e par le forgesort pour lui servir de serviteur et de garde du corps. Il comprend des ordres simples, comme suivre, attaquer, monter la garde, mais il est incapable d'actions complexes ou n\xe9cessitant une motricit\xe9 fine (comme de la couture par exemple!). GOLEM CR\xc9ATURE NON VIVANTE | AGI -1 | CON +10 | FOR +1 | PER -3 | | CHA -4 | INT -3 | VOL +4 | (S) D\xe9fense [10 + rang dans la voie] (V) Points de vigueur [niv. du forgesort \xd7 5] (I) Initiative [Init. du forgesort] Attaque [attaque magique du forgesort] \xb7 DM 1d4\xb0+1",!1)
B.JA=new A.t(3,"Protecteur","G","Une fois par round, s'il est au contact d'un personnage, le golem peut s'interposer et subir les DM d'une attaque \xe0 sa place.",!1)
B.LF=new A.t(4,"Statuette","A","Le forgesort transforme son golem en statuette d'une douzaine de centim\xe8tres de haut, recouverte de runes. Sous forme de statuette, le golem ne peut pas agir, mais il b\xe9n\xe9ficie d'une RD 10. \xc0 tout moment, le forgesort peut utiliser une action de mouvement pour jeter la figurine au sol et lui rendre sa taille normale et toutes ses fonctions.",!0)
B.K8=new A.t(5,"Golem sup\xe9rieur","","Le forgesort peut am\xe9liorer son golem en choisissant une option parmi les suivantes. Le joueur peut choisir une option diff\xe9rente suppl\xe9mentaire \xe0 chaque fois qu'il atteint le rang 5 dans une voie de forgesort. Armure : +5 en DEF Forme de f\xe9lin : +3 en AGI et en DEF, d\xe9 bonus en AGI Baliste : port\xe9e 20 m, [1d4\xb0+AGI] DM Grande taille : +2 PV par niveau et +1 en FOR et DM Vol : des \xab sauts \xbb de 40 m en action limit\xe9e Cerveau am\xe9lior\xe9 : +2 en INT, PER et CHA, dou\xe9 de parole Puissant : +2 en FOR et aux DM, d\xe9 bonus en FOR Arme \xe0 deux mains : +1d4\xb0 aux DM au contact PARTICULARIT\xc9S LI\xc9ES AU GOLEM Soigner un golem : le golem ne gu\xe9rit pas naturellement, mais le forgesort peut le r\xe9parer au rythme de [1d6 par rang + INT] PV par heure. Golem \xe0 0 PV : si le golem est r\xe9duit \xe0 0 PV, il cesse de fonctionner, mais le forgesort peut le r\xe9parer. Mort d'un golem : si le golem est d\xe9truit ou perdu, le forgesort peut en construire un nouveau en 1d6 + 3 jours (+1d6 jours par am\xe9lioration de golem sup\xe9rieur). Un forgesort peut utiliser tous les mat\xe9riaux \xe0 sa disposition dans son environnement, par exemple pierre et bois s'il est dans une for\xeat.",!1)
B.a1d=A.a(s([B.N7,B.LR,B.JA,B.LF,B.K8]),t.P)
B.akY=new A.b5("forgesort_voie-du-golem","Voie du Golem",B.a1d)
B.Jx=new A.t(1,"Morsure de la forge","M","Au prix d'une action de mouvement, le forgesort peut enflammer son b\xe2ton ou son marteau pendant INT minutes et ajoute +2 DM de feu sur les attaques au contact r\xe9alis\xe9es avec cette arme. Ce bonus augmente de +1 chaque fois que le personnage atteint le rang 4 dans une voie de forgesort. L'arme s'\xe9teint imm\xe9diatement s'il la l\xe2che. En plus de ce sort, le forgesort ajoute son rang + 2 aux tests d'orf\xe8vrerie ou de forge.",!0)
B.Ky=new A.t(2,"M\xe9tal br\xfblant","M","Le forgesort doit r\xe9ussir un test oppos\xe9 d'attaque magique (port\xe9e 20 m) pour faire chauffer un objet m\xe9tallique port\xe9 par sa cible pendant [1d4+INT] rounds. S'il s'agit d'une arme, elle inflige 1 DM par round \xe0 son porteur et un malus de -2 aux tests d'attaque. S'il s'agit d'une armure, elle inflige 1d4\xb0 DM par round \xe0 son porteur (au tour du forgesort). La victime peut se d\xe9barrasser pr\xe9cipitamment de son armure au prix d'une action limit\xe9e (elle perd le bonus de DEF associ\xe9; dans le cas d'un adversaire, le MJ devra \xe9valuer ce montant).",!0)
B.LO=new A.t(3,"Magn\xe9tisme","A","Le forgesort contr\xf4le le magn\xe9tisme autour de lui pendant INT minutes. Il obtient un bonus de +2 en DEF contre les attaques des armes m\xe9talliques (au contact ou \xe0 distance). De plus, il divise par deux les DM de tous les projectiles \xe0 pointes m\xe9talliques (fl\xe8ches, carreaux, armes de lancer, etc.).",!0)
B.JJ=new A.t(4,"M\xe9tal hurlant","A","Sur un test oppos\xe9 d'attaque magique r\xe9ussi (port\xe9e 10 m), le forgesort d\xe9forme une pi\xe8ce d'\xe9quipement m\xe9tallique port\xe9e par sa cible. Une arme devient inutilisable et bonne pour le rebut, une armure impose l'utilisation d'un d\xe9 malus \xe0 tous les tests d'attaque et d'AGI de son porteur. La victime peut se d\xe9barrasser de son armure au prix d'une action limit\xe9e. Si l'objet est magique, le sort ne fait effet que pendant un seul round (et ne peut pas \xeatre renouvel\xe9). Appliqu\xe9 \xe0 une structure (par exemple, une porte blind\xe9e), ce sort inflige 3d4\xb0 DM en divisant par deux sa RD.",!0)
B.LX=new A.t(5,"Endurer","","Le forgesort est habitu\xe9 aux travaux et \xe0 la chaleur de la forge. Il divise par deux tous les DM de feu subis et augmente sa CON de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CON. Finalement, il peut ajouter sa valeur de CON au nombre de PM qu'il obtient. SCIENCE, PAS SCIENCE? Ce profil est particuli\xe8rement adapt\xe9 aux univers o\xf9 le d\xe9veloppement technologique n'est pas en reste (tendance steampunk). Dans ce genre d'univers, vous pouvez renommer la voie du golem en voie du m\xe9ca et d\xe9crire les effets comme provenant d'objets \xe9tranges port\xe9s, ing\xe9r\xe9s ou greff\xe9s...",!1)
B.a2A=A.a(s([B.Jx,B.Ky,B.LO,B.JJ,B.LX]),t.P)
B.alA=new A.b5("forgesort_voie-du-metal","Voie du M\xe9tal",B.a2A)
B.a1U=A.a(s([B.aly,B.alu,B.alJ,B.akY,B.alA]),t.oy)
B.M1=new A.t(1,"Projectile de mana","A","Le magicien choisit une cible visible situ\xe9e \xe0 moins de 30 m et lance sur elle un projectile d'\xe9nergie \xe9sot\xe9rique pure, d\xe9formant la trame de la r\xe9alit\xe9. La cible subit automatiquement 1d4\xb0 DM. Si le joueur obtient le r\xe9sultat maximal sur son d\xe9 de dommages, il peut le relancer et ajouter le nouveau r\xe9sultat (une seule fois). Les DM du projectile de mana augmentent de +1 chaque fois que le personnage atteint le rang 4 dans une voie de magicien jusqu'\xe0 un maximum \xe9gal \xe0 sa valeur d'INT.",!0)
B.L8=new A.t(2,"L\xe9vitation","M","Le magicien peut se d\xe9placer verticalement de 5 m par action de mouvement vers le haut ou de 10 m vers le bas pendant INT minutes. Rester en vol stationnaire \xe0 la m\xeame hauteur demande une action de mouvement.",!0)
B.IO=new A.t(3,"Forme gazeuse","A","Le magicien prend la consistance d'un gaz pendant 1 min. Il se d\xe9place au ras du sol (s'il chute, il le fait au ralenti) \xe0 une vitesse de 5 m par action de mouvement (M). Il peut s'introduire par les plus petits interstices (comme sous une porte), mais ne peut utiliser aucune capacit\xe9. Sous cette forme, les armes ordinaires ne lui infligent aucun DM, mais la magie et les armes magiques l'affectent normalement.",!0)
B.JQ=new A.t(4,"Acc\xe9l\xe9ration","A","Le magicien voit son m\xe9tabolisme s'acc\xe9l\xe9rer pendant [1d4\xb0+INT] rounds. Il re\xe7oit imm\xe9diatement une action de mouvement suppl\xe9mentaire, puis une action de mouvement suppl\xe9mentaire \xe0 chaque round. \xc0 son tour, il peut choisir de sacrifier cette action de mouvement pour obtenir au choix +3 en DEF pendant un round ou -1 PM sur le lancement d'un sort \xe0 ce round. Il est possible de cumuler cette r\xe9duction de -1 PM avec une Concentration (L) (voir le chapitre \xab La magie \xbb, page 227). Par exemple, une D\xe9sint\xe9gration lanc\xe9e de cette fa\xe7on co\xfbtera 5 - 2 - 1 = 2 PM.",!0)
B.LY=new A.t(5,"D\xe9sint\xe9gration","A","Le magicien projette un rayon mortel dont la port\xe9e est de 20 m et qui annule la coh\xe9sion de la mati\xe8re, ne laissant derri\xe8re lui qu'un amas de poussi\xe8re. Un test d'attaque magique r\xe9ussi contre la DEF de la cible inflige [5d4\xb0+INT] DM. Si le magicien vise un objet port\xe9 par une cr\xe9ature, le test d'attaque subit un d\xe9 malus. Les objets magiques sont insensibles \xe0 ce sort et les objets normaux (jusqu'\xe0 100 kg) sont r\xe9duits en poussi\xe8re. Une cr\xe9ature r\xe9duite \xe0 0 PV par ce sort est proprement d\xe9sint\xe9gr\xe9e, ne laissant aucun cadavre derri\xe8re elle! (Ses objets magiques sont \xe9pargn\xe9s).",!0)
B.a1i=A.a(s([B.M1,B.L8,B.IO,B.JQ,B.LY]),t.P)
B.alF=new A.b5("magicien_voie-de-la-magie-des-arcanes","Voie de la Magie des Arcanes",B.a1i)
B.Ln=new A.t(1,"Arc de feu","A","Des flammes jaillissent des doigts tendus du magicien. Jusqu'\xe0 3 cibles au contact subissent [1d4\xb0+INT] DM, les cibles peuvent faire un test d'AGI difficult\xe9 [10 + INT] pour ne subir que la moiti\xe9 des DM. Les DM passent \xe0 2d4\xb0 au rang 4.",!0)
B.LW=new A.t(2,"Saper les forces","A","Le magicien choisit une cible vivante situ\xe9e \xe0 une distance maximum de 10 m. S'il r\xe9ussit un test oppos\xe9 d'attaque magique, la cible subit un malus de -2 \xe0 ses tests de FOR, d'attaque au contact et aux DM, jusqu'\xe0 la fin du combat. Le sort n'est pas cumulable plusieurs fois sur la m\xeame cible.",!0)
B.MV=new A.t(3,"Fl\xe8che de feu","A","Le magicien choisit une cible situ\xe9e \xe0 moins de 30 m. Si son attaque magique r\xe9ussit (contre DEF), la cible subit [3d4\xb0+INT] DM. Chaque round de combat suivant, le feu inflige 1d6 DM suppl\xe9mentaires. Sur un r\xe9sultat de 1 ou 2, le sort prend fin. Les DM sur la dur\xe9e ne sont pas cumulables si le sort est lanc\xe9 plusieurs fois.",!0)
B.NG=new A.t(4,"Explosion de feu","A","Le magicien choisit un point situ\xe9 \xe0 moins de 30 m. Toutes les cr\xe9atures (y compris le magicien et ses compagnons) se trouvant dans un rayon de 5 m autour de ce point subissent [4d4\xb0+INT] DM et peuvent effectuer un test d'AGI difficult\xe9 [10 + INT] pour ne subir que la moiti\xe9 des DM.",!0)
B.J7=new A.t(5,"Appel de la foudre","A","Le magicien projette des traits de foudre sur toutes les cibles de son choix dans un rayon de 10 m autour de lui. Il fait un seul test d'attaque magique et toutes les cr\xe9atures cibl\xe9es dont il atteint la DEF subissent [2d4\xb0+INT] DM d'\xe9lectricit\xe9. Note : Le joueur peut d\xe9cider de substituer un \xe9l\xe9ment \xe0 un autre lors de l'acquisition d'un sort, par exemple Mains \xe9lectriques, Explosion acide et Temp\xeate de glace. Toutefois ce choix est d\xe9finitif.",!0)
B.a_L=A.a(s([B.Ln,B.LW,B.MV,B.NG,B.J7]),t.P)
B.al_=new A.b5("magicien_voie-de-la-magie-destructrice","Voie de la Magie Destructrice",B.a_L)
B.MO=new A.t(1,"Asphyxie","A","Si le magicien r\xe9ussit un test oppos\xe9 d'attaque magique (avec une port\xe9e de 20 m), la cr\xe9ature cibl\xe9e est priv\xe9e d'air. La victime \xe9touffe progressivement et subit 1d4\xb0 DM par round pendant INT rounds. Les cr\xe9atures qui ne respirent pas (morts-vivants, cr\xe9atures artificielles) sont immunis\xe9es \xe0 ce sort. En revanche, les r\xe9ductions de dommages (voie du colosse, par exemple) ne s'appliquent pas.",!0)
B.Ms=new A.t(2,"Ma\xeetrise des \xe9l\xe9ments","M","Le magicien retranche son rang + 2 \xe0 tous les DM de feu, de froid, d'\xe9lectricit\xe9 ou d'acide subis pendant INT minutes. De plus, pendant la dur\xe9e du sort, lorsqu'il lance un sort d'un \xe9l\xe9ment, le magicien peut \xe9changer un \xe9l\xe9ment contre un autre (par exemple, une explosion de froid ou une fl\xe8che acide).",!0)
B.LL=new A.t(3,"Arme \xe9l\xe9mentaire","A","Le magicien peut enchanter, en la touchant, une arme au contact ou \xe0 distance pour INT minutes. S'il s'agit de son arme, l'incantation est une action d'attaque (A); si elle appartient \xe0 autrui, c'est une action limit\xe9e (L). Si l'arme change de main, le sort prend fin. L'arme inflige +1d4\xb0 DM de feu, de froid, d'\xe9lectricit\xe9 ou d'acide en plus des DM habituels. Le magicien doit choisir l'\xe9l\xe9ment au moment de l'incantation. Tant qu'il tient l'arme \xe9l\xe9mentaire en main, les sorts bas\xe9s sur cet \xe9l\xe9ment lui co\xfbtent 1 PM de moins pour \xeatre lanc\xe9s (par exemple, Mains br\xfblantes ou Explosion de feu s'il a enflamm\xe9 son b\xe2ton). Ce sort ne fait aucun effet sur une arme qui b\xe9n\xe9ficie d\xe9j\xe0 d'un bonus \xe9l\xe9mentaire aux DM.",!0)
B.Lk=new A.t(4,"Respiration aquatique","A","Le magicien peut respirer sous l'eau pendant 10 minutes. Cette capacit\xe9 peut \xeatre \xe9tendue \xe0 un compagnon par point d'INT.",!0)
B.JY=new A.t(5,"Armure de pierre","A","Pendant INT minutes, le magicien retranche 5 points \xe0 tous les DM subis. Le sort prend fin d\xe8s qu'il a absorb\xe9 [niveau du magicien \xd7 3] DM. Cette r\xe9duction se cumule \xe0 celle offerte par la Ma\xeetrise des \xe9l\xe9ments. Armure de pierre est incompatible avec le sort D\xe9phasage (voie de la magie protectrice), il y met fin imm\xe9diatement.",!0)
B.a2o=A.a(s([B.MO,B.Ms,B.LL,B.Lk,B.JY]),t.P)
B.al7=new A.b5("magicien_voie-de-la-magie-elementaire","Voie de la Magie \xc9l\xe9mentaire",B.a2o)
B.Kp=new A.t(1,"Armure de mana","M","Le magicien fait appara\xeetre une protection magique chatoyante qui recouvre son corps et produit des \xe9tincelles \xe0 chaque fois qu'il encaisse un coup. Pendant INT minutes, la DEF du magicien augmente de +3. Cette valeur passe \xe0 +4 lorsque le personnage atteint le rang 3 dans la voie et augmente de +1 suppl\xe9mentaire chaque fois que le personnage atteint le rang 5 dans une voie de magicien (ou dans la voie du mage). Ce sort ne se cumule jamais \xe0 une armure (il est consid\xe9r\xe9 comme une armure).",!0)
B.Mm=new A.t(2,"Chute ralentie","G","Le magicien peut d\xe9signer un nombre de cibles maximal (dont lui-m\xeame) \xe9gal \xe0 son INT \xe0 une port\xe9e de 10 m, m\xeame en dehors de son tour. Les cibles peuvent chuter de n'importe quelle hauteur sans subir de dommages. En cas de chute inattendue, le magicien doit faire un test d'INT difficult\xe9 15 pour chacun de ses compagnons afin d'avoir le temps de lancer le sort (r\xe9ussite automatique sur lui-m\xeame).",!0)
B.Md=new A.t(3,"D\xe9phasage","A","Pendant [1d4\xb0+INT] rounds, le corps du magicien se d\xe9sincarne par intermittence, son image se brouille et tous les DM des attaques de contact ou \xe0 distance qu'il subit et qu'il inflige sont divis\xe9s par 2. Les DM des sorts ne sont pas r\xe9duits. Un personnage sous l'effet d'un sort d'armure de pierre ne peut se d\xe9phaser.",!0)
B.J6=new A.t(4,"Cercle de protection","A","Le magicien peut tracer un cercle sur le sol (environ 2 m de diam\xe8tre) afin de se prot\xe9ger et d'inclure \xe0 sa protection un nombre de personnes \xe9gal \xe0 son INT. Une fois par round, lorsqu'un sort prend pour cible un personnage prot\xe9g\xe9, le magicien fait un test d'attaque magique oppos\xe9 avec l'auteur du sort. Si le test est r\xe9ussi, le sort adverse est annul\xe9 et n'a aucun effet. De plus, toutes les cr\xe9atures invoqu\xe9es (\xe9l\xe9mentaires, d\xe9mons) et les morts-vivants qui veulent attaquer une cr\xe9ature dans le cercle subissent un d\xe9 malus en attaque. Si le magicien sort du cercle, le sort est dissip\xe9.",!0)
B.M_=new A.t(5,"Interruption du temps","A","Apr\xe8s avoir lanc\xe9 ce sort, le personnage b\xe9n\xe9ficie d'INT rounds complets hors du temps durant lesquels il peut utiliser des sorts ou des objets (potions) sur lui-m\xeame. Il ne peut interagir avec son environnement, ni se d\xe9placer, seulement utiliser son propre \xe9quipement ou ses capacit\xe9s sur lui-m\xeame.",!0)
B.a0Q=A.a(s([B.Kp,B.Mm,B.Md,B.J6,B.M_]),t.P)
B.all=new A.b5("magicien_voie-de-la-magie-protectrice","Voie de la Magie Protectrice",B.a0Q)
B.N4=new A.t(1,"Lumi\xe8re","L","Le magicien d\xe9signe un objet \xe0 moins de 10 m. Celui-ci produit de la lumi\xe8re dans un rayon de 10 m pendant INT heures. Cette source de lumi\xe8re n'\xe9met pas de chaleur. Une fois par combat, le magicien peut lancer ce sort sur les yeux d'une cr\xe9ature dont le NC ne d\xe9passe pas le rang atteint dans la voie. S'il r\xe9ussit un test oppos\xe9 d'attaque magique, elle est aveugl\xe9e pendant 1 round.",!0)
B.Jk=new A.t(2,"Familier","A","Le magicien choisit un petit animal (\xe9cureuil, corbeau, chat, dragonnet). Il peut utiliser les sens de son familier (voir par ses yeux, entendre ce qu'il entend, etc.) et communiquer avec lui \xe0 distance illimit\xe9e. Il gagne +2 en Initiative et en DEF lorsque son familier est en vue. S'il est r\xe9duit \xe0 0 PV, le familier dispara\xeet dans un nuage de fum\xe9e et le personnage perd 1d4\xb0 PV en contrecoup. Toutefois, le ma\xeetre pourra \xe0 nouveau invoquer son familier d\xe8s qu'il aura termin\xe9 une r\xe9cup\xe9ration compl\xe8te (c'est toujours le m\xeame animal qui appara\xeet). Le familier r\xe9cup\xe8re tous les PV perdus apr\xe8s une r\xe9cup\xe9ration rapide. FAMILIER | AGI +3* | CON 0 | FOR -4 | PER +2 | | CHA -2 | INT -2 | VOL +2 | (S) D\xe9fense [13 + rang dans la voie] (V) Points de vigueur [niveau du magicien] (I) Initiative [Init. du magicien] Un familier est une cr\xe9ature trop petite pour attaquer et infliger des dommages.",!0)
B.Nu=new A.t(3,"Invisibilit\xe9","A","Le magicien se rend invisible pendant [1d4\xb0+INT] minutes. Une fois invisible, personne ne peut plus d\xe9tecter sa pr\xe9sence ou lui porter d'attaque directe. Si le magicien attaque, il redevient visible. \xc0 partir du rang 5, le magicien peut lancer ce sort sur un alli\xe9 au prix d'une action limit\xe9e.",!0)
B.Nf=new A.t(4,"Vol","A","Le magicien peut voler pendant [2d4\xb0+INT] minutes. Sa vitesse de d\xe9placement est la m\xeame qu'au sol. Il peut rester en vol stationnaire s'il le d\xe9sire et cela est une action gratuite.",!0)
B.NX=new A.t(5,"T\xe9l\xe9portation","L","Une fois par jour, le magicien dispara\xeet et r\xe9appara\xeet \xe0 un autre endroit situ\xe9 \xe0 moins de (niveau x INT) kilom\xe8tres. Le lieu d'arriv\xe9e doit \xeatre soit en vue, soit parfaitement connu par le magicien. Le magicien peut emmener avec lui un alli\xe9 \xe0 partir du niveau 10, un deuxi\xe8me au niveau 13, un troisi\xe8me au niveau 16 et enfin un quatri\xe8me au niveau 19.",!0)
B.a2r=A.a(s([B.N4,B.Jk,B.Nu,B.Nf,B.NX]),t.P)
B.alI=new A.b5("magicien_voie-de-la-magie-universelle","Voie de la Magie Universelle",B.a2r)
B.a2v=A.a(s([B.alF,B.al_,B.al7,B.all,B.alI]),t.oy)
B.IS=new A.t(1,"Un pied dans la tombe","A","Le sorcier d\xe9signe une cible vivante \xe0 port\xe9e (10 m) et doit r\xe9ussir un test oppos\xe9 d'attaque magique. En cas de succ\xe8s, la cible ressent une douleur intense \xe0 l'emplacement du c\u0153ur, elle subit [1d4\xb0+INT] DM et, si elle rate un test de CON difficult\xe9 10, l'\xe9tat ralenti durant 1 round.",!0)
B.N9=new A.t(2,"Armure d'os","","Le sorcier peut d\xe9sormais porter une armure d'os (souvent camoufl\xe9e sous une robe) qui lui offre un bonus de +3 en DEF et n'emp\xeache pas l'utilisation des capacit\xe9s de sorcier. Son bonus de DEF augmente de +1 chaque fois que le personnage atteint le rang 4 dans une voie de sorcier. Le sorcier doit confectionner cette armure lui-m\xeame \xe0 partir d'ossements et l'entretenir par magie 10 min chaque jour.",!1)
B.KS=new A.t(3,"Animation des morts","L","Le sorcier anime le cadavre d'un humano\xefde de taille moyenne, d\xe9c\xe9d\xe9 depuis moins d'INT jours. Le zombie comprend les ordres \xab Attaquer \xbb, \xab Suivre \xbb, \xab Garder \xbb et \xab Pas bouger \xbb. Le sorcier peut contr\xf4ler un seul zombie, plus un zombie chaque fois qu'il atteint le rang 5 dans une voie de sorcier. Un zombie r\xe9duit \xe0 0 PV tombe en poussi\xe8re. ZOMBIE | AGI -1 | CON +1 | FOR +2 | PER -2 | | CHA -4 | INT -4 | VOL +6 | (S) D\xe9fense 10 (V) Points de vigueur [10 + niveau] (I) Initiative 8 Attaque au contact [attaque magique du sorcier] \xb7 DM 1d4\xb0+2 Le zombie se d\xe9place de 5 m par action de mouvement.",!0)
B.IT=new A.t(4,"Ensevelissement","L","Une fois par combat, si le sorcier r\xe9ussit un test oppos\xe9 d'attaque magique (port\xe9e 20 m), des mains squelettiques surgissent sous les pieds d'une cible de taille moyenne ou inf\xe9rieure et l'enterrent vivante. Tant qu'elle est ensevelie, elle subit 2d4\xb0 DM par round, ne peut agir ni \xeatre la cible d'attaques ext\xe9rieures. \xc0 son tour, elle peut tenter de sortir de terre en r\xe9ussissant un test de FOR ou d'AGI (au choix de la cible) difficult\xe9 15 au prix d'une action limit\xe9e. Si elle tombe \xe0 0 PV, elle reste enterr\xe9e et d\xe9c\xe8de au tour suivant. Chaque personne qui creuse pour l'aider lui octroie un bonus de +2 sur son test (maximum +10).",!0)
B.KD=new A.t(5,"Arm\xe9e des morts","L","Une fois par jour, le sorcier peut invoquer d'innombrables squelettes qui \xe9mergent du sol pour attaquer ses ennemis pendant [niveau du sorcier] rounds. Tous les adversaires situ\xe9s dans un rayon de 10 m autour du sorcier subissent automatiquement 2d4\xb0 DM par round. Les squelettes se d\xe9placent avec le sorcier, mais tous les d\xe9placements dans cette zone (m\xeame ceux du sorcier) sont divis\xe9s par deux.",!0)
B.a_h=A.a(s([B.IS,B.N9,B.KS,B.IT,B.KD]),t.P)
B.akI=new A.b5("sorcier_voie-de-l-outre-tombe","Voie de l'Outre-Tombe",B.a_h)
B.Lc=new A.t(1,"Siphon des \xe2mes","","Une fois par round, lorsqu'une cr\xe9ature humano\xefde vivante meurt \xe0 moins de 20 m du sorcier, il r\xe9cup\xe8re NC PV (arrondis \xe0 1 pour NC \xbd). \xc0 partir du rang 3, si la cr\xe9ature est de NC sup\xe9rieur \xe0 4, il peut choisir de r\xe9cup\xe9rer 1 PM au lieu des PV.",!1)
B.La=new A.t(2,"Masque mortuaire","M","Le sorcier prend l'apparence de la mort pendant INT minutes. Il est alors consid\xe9r\xe9 non-vivant et devient immunis\xe9 \xe0 la plupart des pouvoirs des morts-vivants (drain de vigueur et affaiblissement, paralysie de la goule, etc.). De plus, ceux-ci le prennent pour l'un des leurs. Il divise par deux tous les DM de froid. Il ne peut pas b\xe9n\xe9ficier de soins tant qu'il est sous l'effet de ce sort. Note : Les cr\xe9atures non vivantes sont infatigables, ne respirent pas et sont immunis\xe9es aux maladies, aux poisons et \xe0 la plupart des attaques qui demandent un test de CON. Elles voient dans le noir comme dans de la p\xe9nombre \xe0 une distance de 30 m.",!0)
B.O4=new A.t(3,"Baiser du vampire","A","Ce sort n\xe9cessite la r\xe9ussite d'un test oppos\xe9 d'attaque magique (port\xe9e 30 m). La victime subit [2d4\xb0+INT] DM et le sorcier r\xe9cup\xe8re autant de PV (sans d\xe9passer son maximum de PV).",!0)
B.L7=new A.t(4,"Peur","A","Le sorcier effectue un test oppos\xe9 d'attaque magique contre une cible (port\xe9e 20 m). S'il l'emporte, la victime fuit aussi loin du sorcier que possible pendant INT rounds (il lui faut g\xe9n\xe9ralement autant de temps pour revenir!). Les cr\xe9atures dont le NC est sup\xe9rieur ou \xe9gal au niveau du sorcier ne fuient qu'un seul round. Le sorcier peut choisir de lancer ce sort en action limit\xe9e et toutes les cr\xe9atures \xe0 son contact sont affect\xe9es (faire un test d'attaque magique par adversaire).",!0)
B.Ki=new A.t(5,"Briser les c\u0153urs","A","Le sorcier fait mine d'arracher le c\u0153ur de sa victime, puis de broyer dans sa main (l'image du c\u0153ur de la victime appara\xeet dans la main du sorcier). Il doit faire un test oppos\xe9 d'attaque magique contre une cible vivante (port\xe9e 20 m) et, en cas de r\xe9ussite, il inflige [5d4\xb0+INT] DM, la moiti\xe9 en cas de test rat\xe9. Ce sort ne peut affecter une m\xeame cible qu'une seule fois par combat.",!0)
B.a08=A.a(s([B.Lc,B.La,B.O4,B.L7,B.Ki]),t.P)
B.akO=new A.b5("sorcier_voie-de-la-mort","Voie de la Mort",B.a08)
B.Nk=new A.t(1,"T\xe9n\xe8bres","L","Le sorcier invoque une zone fixe de t\xe9n\xe8bres magiques, de 10 m de diam\xe8tre, \xe0 une port\xe9e de 20 m pour une dur\xe9e d'INT minutes. Toutes les cr\xe9atures, m\xeame celles capables de voir dans le noir, sont aveugl\xe9es dans cette zone. En plus de ce sort, le sorcier ajoute son rang + 2 \xe0 tous les tests d'INT bas\xe9s sur les savoirs sombres (d\xe9mons, morts-vivants, rituels impies, etc.).",!0)
B.LI=new A.t(2,"Reptation","M","Pendant INT minutes, le sorcier peut ramper de 5 m par action de mouvement sur les murs et les plafonds. Il peut lancer des sorts dans cette posture.",!0)
B.L1=new A.t(3,"Strangulation","A","En r\xe9ussissant un test oppos\xe9 d'attaque magique (port\xe9e 20 m), le sorcier \xe9touffe une cr\xe9ature vivante. La victime subit un d\xe9 malus \xe0 tous ses tests et [1d4\xb0+INT] DM par round tant que le sorcier maintient sa concentration par une action de mouvement et la d\xe9pense de 1 PM par round. Si la victime sort de la port\xe9e du sort, il prend fin.",!0)
B.Jy=new A.t(4,"Manteau d'ombre","L","Le sorcier s'enveloppe d'ombre pendant INT minutes. Il gagne un d\xe9 bonus \xe0 tous les tests de discr\xe9tion et il impose un d\xe9 malus \xe0 tous les tests d'attaque \xe0 distance qui le prennent pour cible. S'il tombe \xe0 0 PV pendant la dur\xe9e du sort, il peut choisir de dispara\xeetre dans son ombre et de r\xe9appara\xeetre \xe0 1d6 km dans la direction de son choix avec 1d4\xb0 PV, 1d6 min plus tard (une dissipation de la magie (Ma\xeetrise de la magie, voie du mage) lanc\xe9e sur la zone o\xf9 le sorcier a disparu dans son ombre avant sa r\xe9apparition au loin fait appara\xeetre son corps et annule l'effet). Ceci met fin au sort et interdit de le lancer de nouveau avant le prochain cr\xe9puscule.",!0)
B.Kt=new A.t(5,"Pacte t\xe9n\xe9breux","","Le sorcier augmente sa CON de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CON et voit dans le noir comme s'il s'agissait de p\xe9nombre. De plus, lorsqu'il lance un sort, il peut sacrifier 1d4\xb0 PV pour ajouter +2d4\xb0 aux DM de ce sort. S'il s'agit d'un sort dont les DM durent de round en round (comme strangulation), il peut sacrifier 1d4\xb0 PV chaque round.",!1)
B.a17=A.a(s([B.Nk,B.LI,B.L1,B.Jy,B.Kt]),t.P)
B.al2=new A.b5("sorcier_voie-de-la-sombre-magie","Voie de la Sombre Magie",B.a17)
B.NL=new A.t(1,"Mal\xe9diction","M","Le sorcier effectue un test oppos\xe9 d'attaque magique contre une cible \xe0 moins de 20 m. En cas de succ\xe8s, si l'incantation \xe9tait une action de mouvement (M), la victime subit un d\xe9 malus \xe0 son prochain test. Si l'incantation \xe9tait une action limit\xe9e (L), le d\xe9 malus s'applique \xe0 ses 3 prochains tests. Dans tous les cas, la cible ne peut subir les effets de ce sort qu'une fois par combat.",!0)
B.K1=new A.t(2,"Beaut\xe9 de la succube","L","Le sorcier acquiert une beaut\xe9 fascinante pour INT minutes. Il gagne un d\xe9 bonus aux tests de CHA ainsi qu'une attaque de contact n\xe9cessitant un test d'attaque magique (contre DEF, action d'attaque), qui inflige [1d4\xb0+INT] DM. Le sorcier r\xe9cup\xe8re autant de PV (sans d\xe9passer son maximum de PV) que la cible en a perdu.",!0)
B.MY=new A.t(3,"Pacte d\xe9moniaque","G","Le sorcier sacrifie 1d4\xb0 PV et gagne imm\xe9diatement +INT sur le r\xe9sultat d'un d20 qu'il vient de lancer ou en DEF contre une attaque (avant de savoir si une attaque touche). De plus, il ajoute d\xe9sormais sa VOL au nombre de d\xe9s de r\xe9cup\xe9ration (DR) qu'il poss\xe8de.",!1)
B.MN=new A.t(4,"Aspect du d\xe9mon","A","Le sorcier prend l'apparence d'un d\xe9mon ail\xe9 pendant INT minutes. Il gagne un d\xe9 bonus en attaque au contact et +5 en DEF et \xe0 tous les tests physiques (FOR, AGI, CON), mais il ne peut pas utiliser d'arme (ni les arts martiaux). Il peut faire deux attaques de griffes \xe0 [1d4\xb0+INT] DM \xe0 chaque tour, en action limit\xe9e (une seule en action d'attaque) et il peut voler de 10 m par action de mouvement. Note : Ne se cumule pas avec la Beaut\xe9 de la succube.",!0)
B.LB=new A.t(5,"Invocation d'un d\xe9mon","L","En sacrifiant 1d4\xb0 PV, le sorcier invoque un d\xe9mon \xe0 son service pour INT minutes. Ce d\xe9mon poss\xe8de l'apparence d'un humano\xefde muscl\xe9 d'environ 2,30 m dot\xe9 d'une \xe9p\xe9e et d'ailes de chauve-souris. Le d\xe9mon divise par deux tous les DM non magiques subis, les sorts et les armes magiques lui infligent des DM normaux. Il est capable de voler \xe0 une vitesse \xe9quivalente \xe0 un d\xe9placement normal. Lorsque le sorcier atteint le niveau 15, le d\xe9mon devient capable d'attaquer deux fois \xe0 son tour, au prix d'une action limit\xe9e. D\xc9MON | AGI +2 | CON +4* | FOR +5* | PER +2 | | CHA +0 | INT +2 | VOL +4 | (S) D\xe9fense 18 (V) Points de vigueur [niveau du sorcier \xd7 5] (I) Initiative [Init. du sorcier] Attaque au contact [attaque magique du sorcier] \xb7 DM 2d4\xb0+5",!0)
B.ZM=A.a(s([B.NL,B.K1,B.MY,B.MN,B.LB]),t.P)
B.alm=new A.b5("sorcier_voie-du-demon","Voie du D\xe9mon",B.ZM)
B.K6=new A.t(1,"Saignements","A","Le sorcier doit r\xe9ussir un test d'attaque magique (port\xe9e 10 m) contre une difficult\xe9 de [10 + CON de la cible]. Du sang s'\xe9coule de la bouche, du nez, des oreilles et m\xeame des yeux de la victime, qui subit 1d4\xb0 DM par round pendant INT rounds.",!0)
B.Mr=new A.t(2,"Sang mordant","M","Pendant INT minutes, le sang du sorcier se transforme en un acide qui gicle lorsqu'il subit une blessure. Chaque fois qu'un ennemi au contact le blesse, ce dernier subit 1d4\xb0 DM d'acide.",!0)
B.Mq=new A.t(3,"Exsangue","","Le corps du sorcier devient cadav\xe9rique. Il gagne +2 en DEF et ce bonus passe \xe0 +3 au rang 5 (Si le personnage porte une armure autre qu'une armure d'os de sorcier, le bonus est r\xe9duit de 1 point, donc +1 DEF et +2 DEF au rang 5). De plus, lorsqu'il tombe \xe0 0 PV, il peut continuer \xe0 agir, mais avec un d\xe9 malus \xe0 tous ses tests. S'il subit encore au moins 1 DM, il sombre dans l'inconscience.",!1)
B.K7=new A.t(4,"Rituel de sang","A","Le sorcier s'ouvre les veines et sacrifie 1d4\xb0 PV pour cibler une cr\xe9ature vivante (port\xe9e 20 m), la victime saigne \xe0 la moindre blessure. Tous les DM inflig\xe9s \xe0 la cible par des armes tranchantes ou per\xe7antes (griffes et crocs inclus) augmentent de +1d4\xb0 pendant INT rounds.",!0)
B.NN=new A.t(5,"Lien de sang","A","En r\xe9ussissant un test oppos\xe9 d'attaque magique (port\xe9e 20 m), le sorcier tisse un lien avec sa victime. Pendant INT minutes, la moiti\xe9 des DM re\xe7us par le sorcier sont \xe9galement subis par la cible (les DM inflig\xe9s au sorcier ne sont pas pour autant r\xe9duits) et le sorcier peut lui lancer un sort sans la voir (si elle est \xe0 port\xe9e).",!0)
B.a_s=A.a(s([B.K6,B.Mr,B.Mq,B.K7,B.NN]),t.P)
B.ale=new A.b5("sorcier_voie-du-sang","Voie du Sang",B.a_s)
B.a2w=A.a(s([B.akI,B.akO,B.al2,B.alm,B.ale]),t.oy)
B.Kj=new A.t(1,"Ma\xeetre de la survie","","En milieu naturel, le druide ajoute son rang + 2 \xe0 tous les tests de survie (s'orienter, trouver un abri et de la nourriture, \xe9viter les dangers, etc.) dont les tests de r\xe9cup\xe9ration effectu\xe9s chaque nuit. Lorsqu'il dort en milieu naturel, s'il utilise 1 DR, il gu\xe9rit 1d4\xb0 PV suppl\xe9mentaire.",!1)
B.NA=new A.t(2,"Terrains difficiles","","Le druide ne subit aucune p\xe9nalit\xe9 de d\xe9placement en terrain difficile (natation, neige, boue, broussailles, pente abrupte, etc.). Il obtient un bonus de +3 en initiative, et +1 en attaque et en DEF lors d'un combat dans ces conditions.",!1)
B.Ji=new A.t(3,"B\xe2ton de druide","L","Le druide combat avec les deux extr\xe9mit\xe9s de son b\xe2ton de bois noueux (ou de son \xe9pieu). Lorsqu'il utilise cette capacit\xe9, il effectue deux attaques de contact pour lesquelles il peut remplacer sa FOR par son AGI en attaque s'il le souhaite. Il inflige [1d4\xb0+FOR ou AGI au choix] DM par attaque (plus d'\xe9ventuels bonus si l'arme est magique) et il gagne +2 en DEF pendant 1 round.",!1)
B.L2=new A.t(4,"Constitution h\xe9ro\xefque","","Le druide augmente sa CON de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CON.",!1)
B.Kl=new A.t(5,"R\xe9sistant","","Le druide divise par deux tous les DM \xab naturels non magiques \xbb : froid, feu, chutes, poisons\u2026 mais aussi les DM provoqu\xe9s par les animaux ou les insectes (m\xeame g\xe9ants). Cette protection s'\xe9tend aussi \xe0 ses compagnons animaux.",!1)
B.ZL=A.a(s([B.Kj,B.NA,B.Ji,B.L2,B.Kl]),t.P)
B.alj=new A.b5("druide_voie-de-la-nature","Voie de la Nature",B.ZL)
B.Jo=new A.t(1,"Langage des animaux","","Le druide sait communiquer avec les mammif\xe8res. La communication reste primitive et limit\xe9e \xe0 l'intelligence de l'animal et \xe0 son point de vue (pr\xe9dateur, proie, etc.). De plus, il ajoute son rang + 2 \xe0 tous les tests destin\xe9s \xe0 influencer un animal avec lequel il peut communiquer. Chaque fois que le personnage atteint le rang 4 dans une voie de druide, il apprend \xe0 communiquer avec une nouvelle cat\xe9gorie d'animaux de son choix : les oiseaux, les reptiles (et les amphibiens), les poissons (et les mollusques) ou les arthropodes (insectes, araign\xe9es, scorpions, etc.) et enfin les animaux fantastiques (griffon, p\xe9gase, etc.).",!1)
B.JH=new A.t(2,"Petit compagnon","","Le druide choisit un petit animal (\xe9cureuil, corbeau, chat). Il peut utiliser les sens de son familier (voir par ses yeux, entendre ce qu'il entend, etc.) et communiquer avec lui \xe0 distance illimit\xe9e. Il gagne +2 en DEF lorsque son familier est en vue. Le familier r\xe9cup\xe8re tous les PV perdus apr\xe8s une r\xe9cup\xe9ration rapide. S'il est r\xe9duit \xe0 0 PV, le familier prend la fuite et r\xe9appara\xeet aupr\xe8s de son ma\xeetre 24 h plus tard, compl\xe8tement soign\xe9. S'il est tu\xe9 (lors d'un fait de jeu que le MJ juge in\xe9vitable), le druide perd 1d4\xb0 PV en contrecoup et pourra trouver un autre familier au prochain passage de niveau (pas forc\xe9ment le m\xeame animal).",!1)
B.Ne=new A.t(3,"Nu\xe9e d'insectes","A","En r\xe9ussissant un test d'attaque magique contre la DEF de sa cible (port\xe9e 20 m), le druide lib\xe8re sur celle-ci une nu\xe9e d'insectes volants qui piquent, aveuglent et la suivent pendant [3 + PER] rounds. La victime subit 1 DM par round et un malus de -2 \xe0 tous les tests. Les DM de zone d\xe9truisent la nu\xe9e.",!0)
B.KE=new A.t(4,"Masque du pr\xe9dateur","A","Pendant PER minutes, le druide prend les traits d'un fauve ou d'un loup. Il gagne +2 en Initiative, en DEF, en attaque et aux DM au contact et peut voir dans la nuit (comme un elfe).",!0)
B.L4=new A.t(5,"Forme animale","A","Pendant une dur\xe9e de PER minutes, le druide peut prendre la forme d'un animal de taille moyenne ou inf\xe9rieure (minimum une souris) d'une cat\xe9gorie dont il ma\xeetrise la communication (voir rang 1, \xe0 l'exception des animaux fantastiques). Il conserve seulement ses PV, ses valeurs d'INT et de VOL, et acquiert les caract\xe9ristiques, les attaques, la DEF et les capacit\xe9s naturelles de la forme choisie (le vol pour un oiseau, la respiration aquatique pour le poisson, etc.). Le druide ne peut ni utiliser son \xe9quipement ni ses propres capacit\xe9s sous cette forme. Le druide peut reprendre sa forme humaine lorsqu'il le d\xe9sire par une action de mouvement (M).",!0)
B.ZK=A.a(s([B.Jo,B.JH,B.Ne,B.KE,B.L4]),t.P)
B.al5=new A.b5("druide_voie-des-animaux","Voie des Animaux",B.ZK)
B.L0=new A.t(1,"Peau d'\xe9corce","M","La peau du druide prend la consistance de l'\xe9corce. Il b\xe9n\xe9ficie d'un bonus \xe0 la DEF \xe9gal \xe0 +2 pendant PER minutes. Ce bonus augmente de +1 aux rangs 3 et 5. Les effets du sort ne sont pas cumulables au bonus d'une armure m\xe9tallique ou d'un autre sort de protection qui ajoute un bonus de DEF (\xe0 l'exception du Masque du pr\xe9dateur). En plus de ce sort, le druide ajoute son rang + 2 aux tests pour identifier les plantes et conna\xeetre leurs propri\xe9t\xe9s.",!0)
B.Kv=new A.t(2,"Prison v\xe9g\xe9tale","L","Le druide peut commander \xe0 la v\xe9g\xe9tation de pousser et bloquer ses ennemis (mais pas ses alli\xe9s) dans une zone de 10 m de diam\xe8tre (port\xe9e 20 m) pendant PER minutes. Les cibles sont immobilis\xe9es. \xc0 son tour, une cr\xe9ature peut se lib\xe9rer (action d'attaque) avec un test de FOR difficult\xe9 [10 + PER du druide]. En cas de r\xe9ussite, elle n'est plus affect\xe9e par le sort pour le reste du combat.",!0)
B.Ks=new A.t(3,"Fl\xe8che vivante","A","En une action, le druide enchante une fl\xe8che et la tire (il doit tenir un arc en main). Cette fl\xe8che a pour particularit\xe9 de prendre racine dans la plaie et de devenir un arbuste. S'il r\xe9ussit un test d'attaque \xe0 distance, il inflige les DM habituels de son attaque, et au round suivant, la fl\xe8che inflige 3d4\xb0 DM suppl\xe9mentaires. Si la victime est r\xe9duite \xe0 0 PV par ce sort, un jeune arbuste pousse sur son cadavre.",!0)
B.Jw=new A.t(4,"Animation d'un arbre","L","Le druide peut animer un arbre en le touchant. Il combat \xe0 son service pendant [niveau du druide] rounds. Il peut animer un seul arbre \xe0 la fois. L'arbre anim\xe9 poss\xe8de DEF [10 + rang], PV [Niveau \xd7 5], Initiative 8 et inflige 1d4\xb0+3 DM (attaque magique au contact), se d\xe9pla\xe7ant de 5 m par action de mouvement.",!0)
B.JX=new A.t(5,"Porte v\xe9g\xe9tale","A","Une fois par jour, le druide peut p\xe9n\xe9trer dans le tronc d'un gros arbre et sortir de celui d'un autre arbre appartenant \xe0 la m\xeame for\xeat et situ\xe9 \xe0 une distance maximale de PER \xd7 10 km. \xc0 partir du niveau 10 et tous les 4 niveaux suppl\xe9mentaires, le druide peut emmener une personne avec lui.",!0)
B.a0t=A.a(s([B.L0,B.Kv,B.Ks,B.Jw,B.JX]),t.P)
B.akT=new A.b5("druide_voie-des-vegetaux","Voie des V\xe9g\xe9taux",B.a0t)
B.KF=new A.t(1,"Vitesse du f\xe9lin","","Le druide ajoute son rang + 2 aux tests de course, d'escalade ou de saut. De plus, il gagne +3 en Initiative et +1 en DEF. Le bonus de DEF passe \xe0 +2 au rang 3 et +3 au rang 5.",!1)
B.NU=new A.t(2,"Panth\xe8re","","Le druide apprivoise une panth\xe8re (ou un puma) qui lui ob\xe9it au doigt et \xe0 l'\u0153il. La panth\xe8re se d\xe9place \xe0 l'initiative du druide, poss\xe8de DEF [13 + rang dans la voie], PV [niveau du druide \xd7 4] et inflige 1d4+2 DM (attaque magique au contact).",!1)
B.MM=new A.t(3,"Attaque bondissante","L","Le druide ou son f\xe9lin parcourt de 5 \xe0 10 m et b\xe9n\xe9ficie d'un d\xe9 bonus au test d'attaque et de +1d4\xb0 aux DM contre sa cible. Il ne peut pas effectuer d'attaque bondissante s'il est au contact d'un adversaire.",!1)
B.K3=new A.t(4,"Grand f\xe9lin","","La panth\xe8re devient un animal fabuleux ou est remplac\xe9e par un f\xe9lin plus grand (tigre, lion). Le grand f\xe9lin peut servir de monture au druide et il se d\xe9place de 20 m par action de mouvement. Le druide peut communiquer avec son f\xe9lin par t\xe9l\xe9pathie et le gu\xe9rir \xe0 distance en d\xe9pensant ses propres PV (-1 PV au druide par PV octroy\xe9 au f\xe9lin). L'animal fabuleux poss\xe8de DEF [15 + rang], PV [niveau du druide \xd7 5] et inflige 1d4\xb0+5 DM (attaque magique au contact).",!1)
B.Lo=new A.t(5,"Les sept vies du chat","","Cette capacit\xe9 ne peut \xeatre utilis\xe9e que six fois, et pas plus d'une fois par niveau. Lorsque les PV du druide tombent \xe0 0 ou qu'il meurt, le druide peut choisir d'ignorer ce qui a provoqu\xe9 la mort ou l'inconscience ! Le MJ et le joueur doivent se mettre d'accord et trouver une raison plausible (ou pas !) pour expliquer la survie du personnage, et le faire r\xe9appara\xeetre imm\xe9diatement ou un peu plus tard dans l'aventure si n\xe9cessaire.",!1)
B.a0a=A.a(s([B.KF,B.NU,B.MM,B.K3,B.Lo]),t.P)
B.al1=new A.b5("druide_voie-du-fauve","Voie du Fauve",B.a0a)
B.Lj=new A.t(1,"Baies magiques","L","Le druide doit se trouver devant un buisson ou un arbre vivant. Son incantation fait pousser PER fruits qu'il peut cueillir. Chaque fruit offre l'\xe9quivalent d'un repas et rend [1d4\xb0+rang] PV apr\xe8s 1 min \xe0 celui qui le consomme. Les effets de ces fruits ne fonctionnent qu'une fois par jour et par personnage. En plus de ce sort, le druide ajoute son rang + 2 \xe0 tous les tests de vigilance et de discr\xe9tion en pleine nature.",!0)
B.KI=new A.t(2,"For\xeat vivante","","Apr\xe8s un rituel de 30 min, la for\xeat s'\xe9veille dans un rayon de 1 km par rang et devient une alli\xe9e du druide pendant 24 h. Dans ce p\xe9rim\xe8tre, les ennemis du druide sont d\xe9sorient\xe9s et g\xean\xe9s par les branches et les racines. Ils divisent leur d\xe9placement par deux et subissent un d\xe9 malus \xe0 tous les tests de survie, d'orientation, de perception ou de discr\xe9tion. Le druide peut lancer ce sort une seule fois par jour. Si deux druides essaient d'influencer la for\xeat, c'est celui dont le niveau est le plus \xe9lev\xe9 qui l'emporte.",!0)
B.Lp=new A.t(3,"R\xe9g\xe9n\xe9ration","","Une cible touch\xe9e par le druide r\xe9cup\xe8re [3d4\xb0+PER] PV par un rituel de 10 min (la cible et le druide doivent rester au calme). \xc0 partir du rang 5, ce sort permet aussi de faire repousser les membres ou les parties du corps amput\xe9es. Une cible peut b\xe9n\xe9ficier de ce sort seulement une fois par jour.",!0)
B.J5=new A.t(4,"Perception h\xe9ro\xefque","","Le druide augmente sa PER de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de PER. De plus, il ajoute d\xe9sormais sa PER pour calculer ses PM (en plus de sa VOL).",!1)
B.NW=new A.t(5,"Forme d'arbre","A","Le druide peut se transformer en arbre (environ 5 m de hauteur) pendant PER minutes. Il prend les m\xeames caract\xe9ristiques (\xe0 l'exception de l'INT, de la PER et de la VOL) que l'arbre anim\xe9 (voir plus loin), y compris les PV. Sous cette forme, il ne peut pas parler, mais peut utiliser les sorts des voies du protecteur et des v\xe9g\xe9taux. \xc0 la fin du sort, ou s'il est r\xe9duit \xe0 0 PV, il reprend forme humaine et retrouve les PV que le personnage avait au d\xe9but du sort.",!0)
B.a_B=A.a(s([B.Lj,B.KI,B.Lp,B.J5,B.NW]),t.P)
B.akW=new A.b5("druide_voie-du-protecteur","Voie du Protecteur",B.a_B)
B.a15=A.a(s([B.alj,B.al5,B.akT,B.al1,B.akW]),t.oy)
B.MG=new A.t(1,"Mains d'\xe9nergie","L","Par un effort de concentration, le moine peut rendre ses mains intangibles. Au prix d'une action limit\xe9e, \xe0 son tour, il peut faire une attaque \xe0 mains nues avec un bonus en attaque \xe9gal au rang + 2. De plus, m\xeame lorsqu'il n'utilise pas Mains d'\xe9nergie, toutes les attaques \xe0 mains nues du moine sont consid\xe9r\xe9es comme magiques et il peut choisir de remplacer sa FOR aux DM par sa VOL.",!1)
B.Kc=new A.t(2,"Projection du ki","L","Le moine projette une vague de force avec son corps et son esprit \xe0 une distance maximale de 20 m. Un test d'attaque magique r\xe9ussi lui permet d'infliger [1d4\xb0+ VOL] DM. Les DM passent \xe0 [2d4\xb0+ VOL] au rang 4.",!1)
B.JL=new A.t(3,"Invuln\xe9rable","","Le moine ne re\xe7oit que la moiti\xe9 des DM de toutes les sources \xab \xe9l\xe9mentaires \xbb : Feu, froid, foudre, acide\u2026 ainsi que des poisons ou des maladies. \xc0 partir du rang 5, il ne re\xe7oit plus aucun DM ni effet des poisons et des maladies.",!1)
B.L6=new A.t(4,"Pression mortelle","M","Le moine frappe les points par lesquels circule l'\xe9nergie vitale d'une cr\xe9ature vivante. Lorsqu'il combat \xe0 mains nues, le joueur peut choisir de ne pas infliger imm\xe9diatement les DM de ses attaques, il les comptabilise \xe0 part et ajoute +1d4\xb0 aux DM de chaque attaque. \xc0 tout moment dans l'heure qui suit, il peut annoncer une Pression mortelle. Il doit alors r\xe9ussir un test d'attaque au contact contre la DEF de la cible (action limit\xe9e), ce qui lib\xe8re instantan\xe9ment la totalit\xe9 des DM inflig\xe9s jusqu'alors. \xc0 partir du niveau 10, le moine n'a plus besoin de toucher sa cible pour d\xe9clencher cet effet ; dans ce cas, il remplace le test d'attaque au contact par un test oppos\xe9 d'attaque magique, mais n'a droit qu'\xe0 un seul essai.",!1)
B.Lx=new A.t(5,"Asc\xe9tisme","","Le moine ne mange presque plus, et il peut subsister sans eau et sans sommeil pendant [5 + VOL] jours. Il ne subit aucune p\xe9nalit\xe9 durant cette p\xe9riode. De plus, le moine augmente sa CON de +1 et obtient un d\xe9 bonus aux tests de CON.",!1)
B.a0r=A.a(s([B.MG,B.Kc,B.JL,B.L6,B.Lx]),t.P)
B.alz=new A.b5("moine_voie-de-l-energie-vitale","Voie de l'\xc9nergie Vitale",B.a0r)
B.NE=new A.t(1,"Agilit\xe9 du singe","","Le moine ajoute son rang + 2 \xe0 tous ses tests pour effectuer des acrobaties ou esquiver et il gagne +2 en DEF. Ce bonus passe \xe0 +3 au rang 4. Se relever (si le personnage est renvers\xe9) devient une action gratuite.",!1)
B.O1=new A.t(2,"Griffes du tigre","","D\xe9sormais, lorsque le moine obtient un r\xe9sultat de 1 au d\xe9 de DM \xe0 mains nues, il le remplace par le r\xe9sultat maximal du d\xe9. De plus le moine peut choisir d'infliger des DM tranchants ou perforants lorsqu'il combat \xe0 mains nues au lieu de DM contondants.",!1)
B.Mp=new A.t(3,"Morsure du serpent","","Lorsqu'il attaque \xe0 mains nues, le moine augmente de 1 point les chances d'obtenir un critique sur les attaques au contact (par exemple, 19-20 au lieu de 20). De plus, ses coups critiques port\xe9s \xe0 mains nues sont d\xe9sormais si douloureux que la cible est affaiblie pendant 1 round.",!1)
B.LD=new A.t(4,"Fureur du dragon","L","Une fois par combat, le moine peut effectuer une attaque tournoyante qui inflige automatiquement [3d4\xb0+FOR] DM \xe0 tous les adversaires au contact et oblige ceux-ci \xe0 r\xe9ussir un test de FOR difficult\xe9 10 pour ne pas \xeatre renvers\xe9s.",!1)
B.MA=new A.t(5,"Moment de perfection","","Une fois par jour, le moine peut choisir de r\xe9ussir toutes ses attaques automatiquement (pas de critique) et d'esquiver toutes celles qui le prennent pour cible pendant un round. Tout semble aller au ralenti autour de lui\u2026 Il peut utiliser cette capacit\xe9 une fois de plus chaque jour par rang 5 atteint dans une autre voie de moine, mais pas plus d'une fois par combat. De plus le moine augmente d\xe9finitivement de +1 la valeur de sa plus faible caract\xe9ristique (choisir en cas d'\xe9galit\xe9).",!1)
B.a10=A.a(s([B.NE,B.O1,B.Mp,B.LD,B.MA]),t.P)
B.al9=new A.b5("moine_voie-de-la-maitrise","Voie de la Ma\xeetrise",B.a10)
B.NB=new A.t(1,"Pacifisme","","Tant que le moine n'a r\xe9alis\xe9 aucune action offensive dans un combat, il b\xe9n\xe9ficie d'un bonus de +5 en DEF et divise par deux tous les DM subis par des attaques. De plus, il obtient un bonus \xe9gal \xe0 son rang + 2 \xe0 tous les tests d'empathie (pour analyser l'\xe9tat \xe9motionnel d'un interlocuteur) ou \xe0 ceux effectu\xe9s pour apaiser un auditoire ou le convaincre de ne pas avoir recours \xe0 la violence.",!1)
B.MP=new A.t(2,"Transe de gu\xe9rison","","Le moine peut m\xe9diter pendant 10 min et r\xe9cup\xe9rer ainsi [1d4\xb0+VOL] PV. Les soins augmentent de +1d4\xb0 chaque fois que le personnage atteint le rang 4 dans une voie de moine. Il doit terminer une r\xe9cup\xe9ration rapide avant de pouvoir \xe0 nouveau utiliser cette capacit\xe9 et il ne peut pas l'utiliser plus de trois fois par jour.",!1)
B.M2=new A.t(3,"Ma\xeetrise du ki","","Le moine utilise sa force mentale pour augmenter son efficacit\xe9 en combat. Il ajoute sa VOL \xe0 son Initiative et \xe0 ses PV. De plus, il gagne +2 en DEF (ce bonus passe \xe0 +3 au rang 5).",!1)
B.Lr=new A.t(4,"Volont\xe9 h\xe9ro\xefque","","Le moine augmente sa VOL de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de VOL.",!1)
B.JV=new A.t(5,"Projection mentale","L","Une fois par jour, le moine entre en m\xe9ditation et projette son esprit hors de son corps pendant [1d4\xb0+VOL] minutes. Il ressemble \xe0 un ectoplasme de couleur blanche qui se d\xe9place en volant \xe0 la vitesse de 10 m par round. Il peut passer au travers des murs, mais pas des \xeatres vivants ou des barri\xe8res magiques. Le moine ne per\xe7oit le monde que par sa projection mentale, mais ressent les DM qui sont inflig\xe9s \xe0 son corps. Il peut utiliser cette capacit\xe9 une fois de plus chaque jour par rang 5 atteint dans une autre voie de moine. De plus le moine augmente d\xe9finitivement de +1 la valeur de sa plus faible caract\xe9ristique (choisir en cas d'\xe9galit\xe9).",!1)
B.a1S=A.a(s([B.NB,B.MP,B.M2,B.Lr,B.JV]),t.P)
B.als=new A.b5("moine_voie-de-la-meditation","Voie de la M\xe9ditation",B.a1S)
B.Jh=new A.t(1,"Poings de fer","","Lorsqu'il combat \xe0 mains nues, le moine peut (s'il le souhaite) remplacer sa FOR par son AGI pour ses tests d'attaque au contact et il inflige [1d6+FOR] DM l\xe9taux. Ces DM augmentent \xe0 chaque rang suivant : 1d8 au rang 2, 1d10 au rang 3, 1d12 au rang 4 et enfin 2d6 au rang 5.",!1)
B.No=new A.t(2,"Peau de fer","","Le moine gagne un bonus de +2 en DEF et il divise tous les DM temporaires subis par deux. Le bonus de DEF passe \xe0 +3 au rang 5.",!1)
B.IQ=new A.t(3,"Parade de projectiles","G","Le moine peut d\xe9vier un projectile (fl\xe8che, javelot\u2026) une fois par round (sauf si le test d'attaque est un critique ou si l'attaque vient d'une arme \xe0 poudre).",!1)
B.MB=new A.t(4,"D\xe9luge de coups","L","\xc0 son tour, le moine peut effectuer deux attaques au contact sur des cibles de son choix.",!1)
B.KG=new A.t(5,"Puissance du ki","","Le moine peut choisir de s'imposer un d\xe9 malus sur une attaque au contact et ajoute +2d4\xb0 aux DM. Cette capacit\xe9 peut aussi \xeatre utilis\xe9e avec Projection du ki qui est une attaque magique.",!1)
B.a18=A.a(s([B.Jh,B.No,B.IQ,B.MB,B.KG]),t.P)
B.al3=new A.b5("moine_voie-du-poing","Voie du Poing",B.a18)
B.Jm=new A.t(1,"Pas du vent","","Le moine peut se d\xe9placer avant et apr\xe8s avoir attaqu\xe9 (mais il couvre toujours une distance normale, il divise son mouvement en deux). De plus, il gagne +3 en Initiative et son rang + 2 \xe0 tous les tests de saut, de course ou d'escalade.",!1)
B.M0=new A.t(2,"Course du vent","","Le moine se d\xe9place \xe0 une vitesse surhumaine, il gagne +1 en DEF et une action de mouvement lui permet de couvrir 15 m. Au rang 5, le bonus de DEF passe \xe0 +2 et l'action de mouvement lui permet de couvrir 20 m.",!1)
B.K9=new A.t(3,"Course des airs","","Le moine d\xe9fie les lois de la pesanteur et peut se d\xe9placer sur des surfaces qui ne devraient pas supporter son poids. Il peut se d\xe9placer sur l'eau, la neige, le feuillage des arbres ou courir sur un mur vertical. Il doit commencer et terminer son d\xe9placement sur une surface normale. Il n'est plus ralenti par les terrains difficiles et il est d\xe9sormais immunis\xe9 \xe0 l'\xe9tat immobilis\xe9.",!1)
B.JG=new A.t(4,"Agilit\xe9 h\xe9ro\xefque","","Le moine augmente son AGI de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests d'AGI.",!1)
B.O8=new A.t(5,"Passe-muraille","L","Une fois par combat, le moine peut rendre son corps intangible le temps de passer au travers d'un mur d'une \xe9paisseur maximale de VOL m\xe8tres. Il ne peut rester immat\xe9riel qu'un court instant et reprend corps d\xe8s qu'il \xe9merge du mur. Si le mur est trop \xe9pais, la capacit\xe9 ne fonctionne pas. De plus le moine augmente d\xe9finitivement de +1 la valeur de sa plus faible caract\xe9ristique (choisir en cas d'\xe9galit\xe9).",!1)
B.a0n=A.a(s([B.Jm,B.M0,B.K9,B.JG,B.O8]),t.P)
B.al6=new A.b5("moine_voie-du-vent","Voie du Vent",B.a0n)
B.a1W=A.a(s([B.alz,B.al9,B.als,B.al3,B.al6]),t.oy)
B.M3=new A.t(1,"Pr\xe9dicateur","","Le pr\xeatre ajoute son rang + 2 aux tests visant \xe0 convaincre ou convertir son auditoire. De plus, une fois par jour, il r\xe9cup\xe8re 1 PC s'il r\xe9ussit \xe0 convertir une cr\xe9ature (ou un groupe) \xe0 sa religion ou \xe0 convaincre une cr\xe9ature peu encline \xe0 le faire \xe0 suivre ses pr\xe9ceptes.",!1)
B.MF=new A.t(2,"Miracle mineur","A","Le pr\xeatre r\xe9alise un petit miracle. Par exemple, purifier de l'eau croupie pour qu'elle devienne buvable ou des aliments avari\xe9s (mais il ne peut pas en cr\xe9er), apaiser une douleur mineure (qui n'entra\xeene pas de malus) ou m\xeame une douleur majeure pendant un seul round, soigner une maladie b\xe9nigne (rhume, grippe, etc.). Ce sort permet aussi de rendre 1d4\xb0 PV \xe0 une cr\xe9ature \xe0 0 PV.",!0)
B.KX=new A.t(3,"Arme de lumi\xe8re","M","Ce sort permet d'enchanter l'arme du pr\xeatre pour une dur\xe9e de CHA minutes. Elle produit de la lumi\xe8re dans un rayon de 5 m et contre les d\xe9mons et les morts-vivants, elle offre un d\xe9 bonus en attaque et ajoute +1d4\xb0 aux DM. \xc0 partir du rang 5, le pr\xeatre peut utiliser ce sort sur l'arme d'un alli\xe9 au prix d'une action limit\xe9e ou, s'il utilise le sort sur son arme personnelle, infliger +2d4\xb0 DM (au lieu de 1d4\xb0). Le sort prend imm\xe9diatement fin si l'arme quitte les mains du pr\xeatre.",!0)
B.KH=new A.t(4,"Ailes c\xe9lestes","A","Des ailes divines poussent dans le dos du pr\xeatre, qui peut voler \xe0 une vitesse \xe9quivalente \xe0 son d\xe9placement normal pendant CHA minutes. Rester en vol stationnaire avec les ailes c\xe9lestes est une action de mouvement.",!0)
B.Ny=new A.t(5,"Foudres divines","A","La foudre frappe toutes les cr\xe9atures d\xe9sign\xe9es dans un rayon de 10 m autour du pr\xeatre et leur inflige [2d4\xb0+CHA] DM (pas de test d'attaque requis). Ce sort est gourmand en \xe9nergie et son co\xfbt augmente de +1 PM \xe0 chaque utilisation tant que le pr\xeatre n'a pas termin\xe9 une r\xe9cup\xe9ration rapide.",!0)
B.a1L=A.a(s([B.M3,B.MF,B.KX,B.KH,B.Ny]),t.P)
B.akU=new A.b5("pretre_voie-de-la-foi","Voie de la Foi",B.a1L)
B.KZ=new A.t(1,"Arme b\xe9nie","A","Le pr\xeatre effectue un court rituel et son arme est b\xe9nie pour une dur\xe9e de 24 h. Lorsqu'il obtient un r\xe9sultat de 1 sur son d\xe9 de DM, il relance le d\xe9 et garde le second r\xe9sultat. Les DM de l'arme sont consid\xe9r\xe9s comme magiques. L'arme n'est plus b\xe9nie si une autre cr\xe9ature l'utilise.",!0)
B.Nh=new A.t(2,"Bouclier de la foi","","Le pr\xeatre porte le symbole de sa foi sur son bouclier, ce qui lui conf\xe8re un bonus suppl\xe9mentaire de +1 en DEF lorsqu'il l'utilise. Ce bonus passe \xe0 +2 au rang 5. Comme pour l'arme b\xe9nie, le symbole de la foi n'est d'aucune utilit\xe9 si le bouclier est utilis\xe9 par quelqu'un d'autre.",!1)
B.LE=new A.t(3,"Ch\xe2timent divin","L","Le pr\xeatre effectue une attaque de contact avec un d\xe9 bonus et ajoute son CHA aux dommages. De plus, lorsqu'il utilise cette capacit\xe9, le pr\xeatre peut d\xe9penser 1 PM pour ajouter +1d4\xb0 aux DM d'une attaque au contact qui touche. Au rang 5, il peut d\xe9penser 2 PM pour ajouter +2d4\xb0.",!1)
B.N0=new A.t(4,"Marteau de la foi","A","Le pr\xeatre effectue un test d'attaque magique contre la DEF de sa cible (port\xe9e de 30 m). Un projectile d'\xe9nergie de la forme de l'arme du pr\xeatre va percuter la cible, lui infligeant [2d4\xb0+CHA] DM en cas de r\xe9ussite. Si l'arme du pr\xeatre est magique, il peut ajouter son bonus au test d'attaque et aux DM. Les DM du marteau de la foi augmentent de +1 chaque fois que le personnage atteint le rang 4 dans une autre voie de pr\xeatre.",!0)
B.Nq=new A.t(5,"Mot de pouvoir","A","Une fois par jour, le pr\xeatre peut prononcer un mot avec la voix de son dieu. Cela d\xe9passe l'entendement des mortels et tous ses ennemis dans un rayon de 10 m sont \xe9tourdis pendant 1 round (pas d'action et -5 en DEF).",!0)
B.a1m=A.a(s([B.KZ,B.Nh,B.LE,B.N0,B.Nq]),t.P)
B.alM=new A.b5("pretre_voie-de-la-guerre-sainte","Voie de la Guerre Sainte",B.a1m)
B.MQ=new A.t(1,"B\xe9n\xe9diction","L","Le pr\xeatre entonne un chant pour encourager ses compagnons en vue. Ses alli\xe9s et lui b\xe9n\xe9ficient d'un bonus de +1 \xe0 tous leurs tests de caract\xe9ristique et d'attaque pendant CHA minutes. Ce bonus passe \xe0 +2 au rang 5. De plus, le pr\xeatre obtient un bonus \xe9gal \xe0 son rang + 2 \xe0 tous les tests de th\xe9ologie ou de cosmologie.",!0)
B.NO=new A.t(2,"Sanctuaire","L","Pendant 1 min (10 rounds), tous les adversaires qui veulent attaquer le pr\xeatre doivent r\xe9ussir un test d'INT difficult\xe9 [10 + CHA du pr\xeatre]. S'ils \xe9chouent, ils ne peuvent pas l'attaquer pour la dur\xe9e du sort. Ceux dont le niveau est inf\xe9rieur \xe0 la moiti\xe9 de celui du pr\xeatre sont automatiquement affect\xe9s (pas de test d'INT). Si le pr\xeatre commet une action offensive, le sort prend fin imm\xe9diatement et il ne peut plus \xeatre lanc\xe9 avant de prendre une r\xe9cup\xe9ration rapide.",!0)
B.IP=new A.t(3,"Destruction du mal","A","Tous les morts-vivants et les d\xe9mons dans un rayon de 10 m autour du pr\xeatre subissent automatiquement [2d4\xb0+CHA] DM. Les DM passent \xe0 3d4\xb0 au rang 5.",!0)
B.IW=new A.t(4,"Volont\xe9 h\xe9ro\xefque","","Le pr\xeatre augmente sa VOL de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de VOL.",!1)
B.NR=new A.t(5,"Intervention divine","G","Le pr\xeatre fait appel \xe0 son dieu pour changer le cours des \xe9v\xe9nements. Une fois par combat, il peut d\xe9cider qu'un test du MJ ou des joueurs est une r\xe9ussite ou un \xe9chec, m\xeame apr\xe8s que les d\xe9s ont r\xe9v\xe9l\xe9 leur r\xe9sultat. Il ne peut pas modifier le r\xe9sultat du test obtenu par une cr\xe9ature d'un NC sup\xe9rieur \xe0 son niveau.",!1)
B.a0F=A.a(s([B.MQ,B.NO,B.IP,B.IW,B.NR]),t.P)
B.akL=new A.b5("pretre_voie-de-la-priere","Voie de la Pri\xe8re",B.a0F)
B.KJ=new A.t(1,"V\xeatements sacr\xe9s","","La tenue religieuse du pr\xeatre est b\xe9nie et le prot\xe8ge. Lorsqu'il ne porte aucune armure (bouclier autoris\xe9), il obtient un d\xe9 bonus \xe0 tous les tests pour r\xe9sister \xe0 un contr\xf4le mental (injonction, charme, domination\u2026) et +2 en DEF. Ce bonus passe \xe0 +3 au rang 3 et +4 au rang 5. \xc9ventuellement, si le pr\xeatre prie une divinit\xe9 guerri\xe8re, il peut choisir d'obtenir la ma\xeetrise de la cotte de mailles (DEF +5) et l'autorisation d'utiliser les capacit\xe9s des voies de pr\xeatre avec cette armure.",!1)
B.M6=new A.t(2,"Augure","L","Le pr\xeatre entre en contact avec les forces de l'au-del\xe0 et demande un avis sur les cons\xe9quences d'une action (par exemple \xab quelles seront les cons\xe9quences si j'ouvre cette porte ? \xbb). Il doit faire un test de CHA difficult\xe9 10. En cas de succ\xe8s, il re\xe7oit une r\xe9ponse d\xe9termin\xe9e par le MJ parmi : b\xe9n\xe9fique, incertain, risqu\xe9 ou pr\xe9judiciable. Le MJ essaie de donner la r\xe9ponse la plus utile possible au sc\xe9nario.",!0)
B.KR=new A.t(3,"D\xe9livrance","L","En touchant sa cible, le pr\xeatre annule les p\xe9nalit\xe9s inflig\xe9es par les sorts, les mal\xe9dictions et les capacit\xe9s sp\xe9ciales (peur, douleur, affaiblissement, poisons, p\xe9trification, etc., et les \xe9tats \xe9tourdi, paralys\xe9, ralenti ou immobilis\xe9), mais pas les mutilations ou les amputations. Si la p\xe9nalit\xe9 \xe9tait permanente, le MJ peut requ\xe9rir un test d'attaque magique oppos\xe9 et imposer un \xe9ventuel malus selon la force de l'effet.",!0)
B.MD=new A.t(4,"Charisme h\xe9ro\xefque","","Le pr\xeatre augmente son CHA de +1. D\xe9sormais, il obtient un d\xe9 bonus aux tests de CHA.",!1)
B.Nm=new A.t(5,"Marche des plans","L","Une fois par jour, le pr\xeatre peut passer dans une dimension entre les plans d'existence o\xf9 le temps et l'espace sont d\xe9form\xe9s pendant un maximum de CHA rounds. Il se d\xe9place dans une sorte de brouillard gris o\xf9 le paysage d\xe9file \xe0 toute vitesse. Pour chaque round de Marche des plans, il se d\xe9place en r\xe9alit\xe9 de 10 km. Le lieu de sortie n'est cependant pas tr\xe8s pr\xe9cis et le MJ doit d\xe9terminer une position au hasard autour du point vis\xe9 (\xe0 1d6 km pr\xe8s).",!0)
B.a29=A.a(s([B.KJ,B.M6,B.KR,B.MD,B.Nm]),t.P)
B.ald=new A.b5("pretre_voie-de-la-spiritualite","Voie de la Spiritualit\xe9",B.a29)
B.M9=new A.t(1,"R\xe9cup\xe9ration mineure","A","Le pr\xeatre peut apposer les mains sur un alli\xe9 au contact (ou sur lui-m\xeame) pour le soigner. Le patient r\xe9cup\xe8re [1d4\xb0+CHA du pr\xeatre] PV. Ce sort peut \xeatre lanc\xe9 une fois par jour par rang atteint dans la voie, plus une fois suppl\xe9mentaire chaque fois que le personnage atteint le rang 3 dans une autre voie de pr\xeatre. En plus de ce sort, le pr\xeatre ajoute son rang + 2 \xe0 tous les tests de m\xe9decine et de premiers soins.",!0)
B.K2=new A.t(2,"Vigueur divine","L","La cible au contact est gu\xe9rie d'un poison ou d'une maladie. Si l'infection est surnaturelle, un test d'attaque magique (\xe9ventuellement oppos\xe9) peut \xeatre demand\xe9 par le MJ. De plus, le pr\xeatre obtient un bonus \xe9gal au rang + 2 aux tests effectu\xe9s pour r\xe9sister aux maladies et aux poisons.",!0)
B.Jp=new A.t(3,"R\xe9cup\xe9ration majeure","L","Le pr\xeatre peut soigner une cible (ou lui-m\xeame) \xe0 une port\xe9e de 20 m ; elle r\xe9cup\xe8re imm\xe9diatement [3d4\xb0+CHA du pr\xeatre] PV. Le montant des soins prodigu\xe9s augmente de 1d4\xb0 chaque fois que le personnage atteint le rang 5 dans une voie de pr\xeatre.",!0)
B.KN=new A.t(4,"Ph\xe9nix","","Une fois par jour, lorsque le personnage tombe \xe0 0 PV, il se rel\xe8ve, nimb\xe9 d'une aura de lumi\xe8re. Il produit alors une onde d'\xe9nergie positive qui restitue [2d4\xb0+CHA du pr\xeatre] PV \xe0 tous ses alli\xe9s dans un rayon de 20 m, et il r\xe9cup\xe8re lui-m\xeame le double de PV.",!1)
B.N2=new A.t(5,"R\xe9tablissement","","Une fois par jour, le pr\xeatre peut soigner une cr\xe9ature par point de CHA. Chaque patient (\xe9ventuellement lui-m\xeame inclus) obtient les m\xeames effets qu'un sort de R\xe9cup\xe9ration majeure. Le sort prend 10 min pendant lesquelles tous les patients doivent rester au repos dans un rayon de 5 m autour du pr\xeatre qui se concentre et se nimbe de lumi\xe8re divine. Ce sort ne peut pas \xeatre lanc\xe9 avec la r\xe8gle de concentration.",!0)
B.a12=A.a(s([B.M9,B.K2,B.Jp,B.KN,B.N2]),t.P)
B.alG=new A.b5("pretre_voie-des-soins","Voie des Soins",B.a12)
B.a1f=A.a(s([B.akU,B.alM,B.akL,B.ald,B.alG]),t.oy)
B.yb=new A.bg(B.yy,[B.a2D,B.a2x,B.a2k,B.a0u,B.a1h,B.a2d,B.a25,B.a2G,B.a1U,B.a2v,B.a2w,B.a15,B.a1W,B.a1f],A.ai("bg<f,Q<b5>>"))
B.a31=new A.j(33)
B.a32=new A.j(34)
B.a33=new A.j(35)
B.a34=new A.j(36)
B.a35=new A.j(37)
B.a36=new A.j(38)
B.a37=new A.j(39)
B.a38=new A.j(40)
B.a39=new A.j(41)
B.tn=new A.j(42)
B.xQ=new A.j(43)
B.a3a=new A.j(44)
B.xR=new A.j(45)
B.xS=new A.j(46)
B.xT=new A.j(47)
B.xU=new A.j(48)
